];

import { CONFIG } from '../constants';
import { DashboardData, AdvisorData } from '../types';

// Helper to parse currency strings like "$ 1.234,50" or "1,234.50"
const parseCurrency = (value: string | null | undefined): number => {
  if (!value) return 0;
  // Remove currency symbols and clean up
  const clean = value.replace(/[^\d.,-]/g, '');

  // Detect format: if comma is after dot or only comma exists near end, it might be decimal
  // Google Sheets HTML often exports consistent format based on locale, but it can be tricky.
  // We assume standard US/International format if direct parsing works, or handle Euro style.

  // Strategy: Replace all non-numeric except last separator
  // However, simpler approach for common dashboard sheets:
  // Remove all characters except numbers, dots, and commas.
  // If it looks like '1.000,00', replace dot with empty, comma with dot.

  if (clean.includes(',') && clean.includes('.')) {
    if (clean.indexOf(',') > clean.indexOf('.')) {
       // 1.000,00 format
       return parseFloat(clean.replace(/\./g, '').replace(',', '.'));
    }
  } else if (clean.includes(',')) {
    // If only comma, assume decimal if length after comma is 2, or thousand if 3?
    // Safer to check the HTML content source, but usually Spanish locale = comma decimal
    return parseFloat(clean.replace(',', '.'));
  }

  return parseFloat(clean);
};

const parseInteger = (value: string | null | undefined): number => {
  if (!value) return 0;
  return parseInt(value.replace(/\D/g, ''), 10) || 0;
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // We use AllOrigins to bypass CORS for the Google Sheets HTML
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(CONFIG.SHEET_URL)}`;
    const response = await fetch(proxyUrl);

    if (!response.ok) {
      throw new Error('Network response was not ok');
    }

    const json = await response.json();
    const htmlContent = json.contents;

    const parser = new DOMParser();
    const doc = parser.parseFromString(htmlContent, 'text/html');
    const table = doc.querySelector('table');

    if (!table) {
      throw new Error('Could not find data table in sheet');
    }

    const rows = Array.from(table.querySelectorAll('tr'));

    // --- PARSING RULES BASED ON PROMPT ---

    // Row 18 (index 17) contains TOTALS
    // Note: Google Sheets often puts a header in the first tr, or row numbers in th.
    // We need to be careful with indices. Usually published HTML matches row numbers closely 
    // if we ignore the first <thead> or verify content.
    // Let's assume the prompt's "Row 18" corresponds to the 18th <tr> in the main body or absolute index 17 (0-based).

    const TOTAL_ROW_INDEX = 17; 
    const GOAL_ROW_INDEX = 40; // Row 41
    const GOAL_COL_INDEX = 1;  // Column B

    // Safe access
    const totalRow = rows[TOTAL_ROW_INDEX];
    const goalRow = rows[GOAL_ROW_INDEX];

    if (!totalRow) throw new Error('Total row (18) not found');

    // Parse Totals
    const totalCells = Array.from(totalRow.querySelectorAll('td'));
    // Structure: [Name(Total), Pedidos, 10:00, 11:00...]
    const totalOrders = parseInteger(totalCells[1]?.textContent);

    // Calculate total sales from hourly columns (Indices 2 to 11 for 10:00-19:00)
    const hourlyTotals: number[] = [];
    let calculatedTotalSales = 0;

    for (let i = 2; i <= 11; i++) {
      const val = parseCurrency(totalCells[i]?.textContent);
      hourlyTotals.push(val);
      calculatedTotalSales += val;
    }

    // Parse Goal
    let dailyTarget = 0;
    if (goalRow) {
      const goalCells = Array.from(goalRow.querySelectorAll('td'));
      dailyTarget = parseCurrency(goalCells[GOAL_COL_INDEX]?.textContent);
    }

    // Fallback if target is 0 or missing to avoid division by zero
    if (dailyTarget === 0) dailyTarget = 1; 

    // Parse Advisors
    // Advisors are typically rows 2/3 down to 16ish. 
    // We will scan all rows, ignore Row 18, ignore header (Row 1), ignore empty names.
    const advisors: AdvisorData[] = [];

    rows.forEach((row, index) => {
      // Skip Total Row and Goal Row area
      if (index === TOTAL_ROW_INDEX || index >= 30) return;

      const cells = Array.from(row.querySelectorAll('td'));
      if (cells.length < 3) return;

      const name = cells[0]?.textContent?.trim();
      // Heuristic: Valid advisor row has a name, name is not "ASESOR" (header), and not empty
      if (!name || name === 'ASESOR' || name.toLowerCase().includes('total')) return;

      const orders = parseInteger(cells[1]?.textContent);
      const hourlySales: number[] = [];
      let advisorTotal = 0;

      for (let i = 2; i <= 11; i++) {
        const val = parseCurrency(cells[i]?.textContent);
        hourlySales.push(val);
        advisorTotal += val;
      }

      advisors.push({
        name,
        orders,
        hourlySales,
        totalSales: advisorTotal
      });
    });

    // Sort advisors by total sales descending
    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales: calculatedTotalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching dashboard data:', error);
    throw error;
  }
};

