interface AdvisorBarChartProps {
  advisors: AdvisorData[];
}

export const AdvisorBarChart: React.FC<AdvisorBarChartProps> = ({ advisors }) => {
  // Top 10 advisors to keep chart clean
  const dataToRender = advisors.slice(0, 10);

  const data = {
    labels: dataToRender.map(a => a.name.split(' ')[0]), // First name only for compactness
    datasets: [
      {
        label: 'Ventas',
        data: dataToRender.map(a => a.totalSales),
        backgroundColor: (context: any) => {
          // Gradient for bars
          const ctx = context.chart.ctx;
          const gradient = ctx.createLinearGradient(0, 0, 0, 400);
          gradient.addColorStop(0, COLORS.BLUE);
          gradient.addColorStop(1, 'rgba(50, 87, 149, 0.4)');
          return gradient;
        },
        borderRadius: 4,
        borderWidth: 0,
      },
    ],
  };

  const options: ChartOptions<'bar'> = {
    ...commonOptions,
    indexAxis: 'y' as const, // Horizontal bar
    plugins: {
      ...commonOptions.plugins,
      title: {
        display: true,
        text: 'Ranking de Asesores (Top 10)',
        color: '#F5F5F5',
        font: { size: 16, weight: 'bold' },
        align: 'start',
        padding: { bottom: 20 }
      }
    },
    scales: {
       x: {
         ...commonOptions.scales?.y, // Swap axes props for horizontal
         grid: { color: 'rgba(255,255,255,0.05)' }
       },
       y: {
         ...commonOptions.scales?.x,
         grid: { display: false }
       }
    }
  };

  return <Bar data={data} options={options} />;
};

