  // Calculate KPIs
  const totalSales = data?.totalSales || 0;
  const totalOrders = data?.totalOrders || 0;
  const target = data?.dailyTarget || 1;
  const progress = totalSales / target;

  return (
    <div className="h-screen w-screen flex flex-col p-4 md:p-6 gap-6 bg-slate-900 relative">

      {/* Header / Info Bar */}
      <div className="flex justify-between items-center mb-2">
         <div>
            <h1 className="text-2xl font-bold text-white tracking-tight flex items-center gap-2">
              <span className="text-blue-500">FARMA</span>PLUS DASHBOARD
            </h1>
            <p className="text-xs text-gray-500 mt-1">
               Última actualización: {lastRefresh.toLocaleTimeString()}
            </p>
         </div>
         {error && (
            <div className="flex items-center gap-2 text-red-500 bg-red-900/20 px-4 py-2 rounded-lg">
              <AlertCircle size={16} />
              <span className="text-sm font-medium">{error}</span>
            </div>
         )}
      </div>

      {/* Top Section: KPIs */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 h-1/4 min-h-[160px]">
        <KpiCard
          title="Venta Total"
          value={formatCurrency(totalSales)}
          subValue="Ingresos del día"
          color={COLORS.BLUE}
          icon={<Activity className="w-6 h-6" />}
        />
        <KpiCard
          title="Pedidos Totales"
          value={totalOrders.toString()}
          subValue="Transacciones procesadas"
          color={COLORS.RED} // Requested Red
          icon={<ShoppingCart className="w-6 h-6" />}
        />
        <KpiCard
          title="% Objetivo Diario"
          value={formatPercentage(progress)}
          subValue={`Meta: ${formatCurrency(target)}`}
          color={progress >= 1 ? COLORS.GREEN : (progress >= 0.7 ? '#fbbf24' : COLORS.RED)}
          icon={<TrendingUp className="w-6 h-6" />}
        />
      </div>

      {/* Center Section: Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 flex-1 min-h-0">
        {/* Left: Advisor Ranking */}
        <div className="rounded-2xl p-4 shadow-lg flex flex-col" style={{ backgroundColor: COLORS.DARK_BG }}>
          <div className="flex-1 min-h-0 relative">
             {data && <AdvisorBarChart advisors={data.advisors} />}
