import { CONFIG } from '../constants';
import { DashboardData, AdvisorData } from '../types';

// Robust CSV Line Parser to handle quoted values (e.g., "Doe, John")
const parseCSVLine = (line: string): string[] => {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current);
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current);
  return result;
};

const parseCurrency = (value: string | undefined): number => {
  if (!value) return 0;
  // Remove quotes, whitespace, and currency symbols
  const clean = value.replace(/['"$]/g, '').trim();

  if (!clean) return 0;

  // Handle European/South American format: 1.234,50 -> 1234.50
  // Check if comma exists and is the last separator
  if (clean.includes(',') && (!clean.includes('.') || clean.indexOf(',') > clean.indexOf('.'))) {
     // Remove dots (thousands), replace comma with dot
     return parseFloat(clean.replace(/\./g, '').replace(',', '.'));
  }

  // Handle US format: 1,234.50 -> 1234.50
  return parseFloat(clean.replace(/,/g, ''));
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  return parseInt(value.replace(/\D/g, ''), 10) || 0;
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // CSV doesn't strictly need a proxy if published to web, but AllOrigins ensures CORS safety
    // For CSV, we can often fetch directly if Google headers allow, but let's stick to proxy for safety.
    // Actually, Google Sheets CSV publish links usually allow CORS. Let's try direct first, fallback to proxy if needed.
    // Given the prompt constraints, we will use the proxy to be safe.

    // Note: AllOrigins returns JSON with a 'contents' string.
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(CONFIG.SHEET_URL)}`;
    const response = await fetch(proxyUrl);

    if (!response.ok) {
      throw new Error('Network response was not ok');
    }

    const json = await response.json();
    const csvText: string = json.contents;

    const rows = csvText.split(/\r?\n/).map(line => parseCSVLine(line));

    // --- MAPPING BASED ON CSV STRUCTURE ---
    // Col 0: Asesor
    // Col 1: Pedidos
    // Col 2-11: Hours 10:00 to 19:00
    // Row 17 (index 17): TOTAL Row (Assuming header is row 0)
    // Row 40 (index 40): Target Row (B41)

    // Find Total Row
    // We look for "TOTAL" in the first column, or fallback to index 17
    let totalRowIndex = rows.findIndex(r => r[0]?.toUpperCase().includes('TOTAL'));
    if (totalRowIndex === -1) totalRowIndex = 17; // Fallback to prompt spec

    const totalRow = rows[totalRowIndex];
    if (!totalRow) throw new Error('Total row not found');

    // Parse Goal (B41 -> Row index 40, Col index 1)
    const goalRowIndex = 40;
    const goalRow = rows[goalRowIndex];
    let dailyTarget = 0;
    if (goalRow && goalRow[1]) {
      dailyTarget = parseCurrency(goalRow[1]);
    }
    if (dailyTarget === 0) dailyTarget = 1; // Prevent div/0

    // Calculate Total Sales & Orders
    const totalOrders = parseInteger(totalRow[1]);

    // Calculate Hourly Totals for Line Chart
    // Columns C (2) through L (11) -> 10 columns
    const hourlyTotals: number[] = [];
    let calculatedTotalSales = 0;

    for (let i = 2; i <= 11; i++) {
      const val = parseCurrency(totalRow[i]);
      hourlyTotals.push(val);
      calculatedTotalSales += val;
    }

    // Process Advisors
    const advisors: AdvisorData[] = [];

    rows.forEach((row, index) => {
      // Filter out invalid rows
      if (index === totalRowIndex || index >= 30) return; // Skip total and bottom area
      if (index < 1) return; // Skip header

      const name = row[0]?.trim();

      // Validation: Name exists, not 'ASESOR', not empty
      if (!name || name === 'ASESOR' || name.toUpperCase().includes('TOTAL')) return;

      const orders = parseInteger(row[1]);
      const hourlySales: number[] = [];
      let advisorTotal = 0;

      // Extract hourly data
      for (let i = 2; i <= 11; i++) {
        const val = parseCurrency(row[i]);
        hourlySales.push(val);
        advisorTotal += val;
      }

      advisors.push({
        name,
        orders,
        hourlySales,
        totalSales: advisorTotal
      });
    });

    // Sort by sales desc
    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales: calculatedTotalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching dashboard data:', error);
    throw error;
  }
};

import React, { useEffect, useState, useCallback, useRef } from 'react';
