// Helper: Delay for retry
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Robust CSV Line Parser
const parseCSVLine = (line: string): string[] => {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current);
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current);
  return result;
};

const parseCurrency = (value: string | undefined): number => {
  if (!value) return 0;
  // Remove quotes, whitespace, and currency symbols
  const clean = value.replace(/['"$]/g, '').trim();
  if (!clean) return 0;

  // Handle European/South American format: 1.234,50 -> 1234.50
  if (clean.includes(',') && (!clean.includes('.') || clean.indexOf(',') > clean.indexOf('.'))) {
     return parseFloat(clean.replace(/\./g, '').replace(',', '.'));
  }
  return parseFloat(clean.replace(/,/g, ''));
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  return parseInt(value.replace(/\D/g, ''), 10) || 0;
};

// Retry wrapper for fetch
const fetchWithRetry = async (url: string, retries = 3, backoff = 1000): Promise<string> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

    // Check if it is a JSON response from proxy
    const contentType = response.headers.get("content-type");
    if (contentType && contentType.includes("application/json")) {
        const json = await response.json();
        return json.contents;
    }

    return await response.text();
  } catch (error) {
    if (retries > 0) {
      console.warn(`Fetch failed, retrying in ${backoff}ms...`, error);
      await delay(backoff);
      return fetchWithRetry(url, retries - 1, backoff * 2);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // Strategy: Try Proxy first as it handles CORS reliably for published sheets
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(CONFIG.SHEET_URL)}`;

    const csvText = await fetchWithRetry(proxyUrl);

    const rows = csvText.split(/\r?\n/).map(line => parseCSVLine(line));

    // --- PARSING LOGIC ---

    // 1. Find TOTAL Row (row starting with "TOTAL")
    // Fallback to row 18 (index 17) if not found by string
    let totalRowIndex = rows.findIndex(r => r[0] && r[0].toUpperCase().trim() === 'TOTAL');
    if (totalRowIndex === -1 && rows.length > 17) totalRowIndex = 17;

    const totalRow = rows[totalRowIndex];
    if (!totalRow) throw new Error('Total row not found');

    // 2. Extract specific KPIs from TOTAL row
    // Pedidos -> Col B (Index 1)
    const totalOrders = parseInteger(totalRow[1]);

    // Monto Total -> Col E (Index 4) per instructions
    // Note: If Col E is 0 or empty, we might want to fallback to summing columns, 
    // but we strictly follow the prompt instructions for the KPI.
    let totalSales = parseCurrency(totalRow[4]);

    // 3. Extract Hourly Totals for Chart
    // Assuming hourly columns are still roughly C (2) through L (11) based on standard layout
    // We sum these to cross-verify or just use them for the chart.
    const hourlyTotals: number[] = [];
    let sumOfHours = 0;
    for (let i = 2; i <= 11; i++) {
      const val = parseCurrency(totalRow[i]);
      hourlyTotals.push(val);
      sumOfHours += val;
    }

    // Safety check: if Col E (Index 4) seems wrong (e.g. 0) but sumOfHours > 0, use sumOfHours
    // This handles the case where Col E isn't actually the total in the specific sheet version
    if (totalSales === 0 && sumOfHours > 0) {
        totalSales = sumOfHours;
    }

    // 4. Daily Target
    // Row 41, Col B -> Index 40, Index 1
    const goalRowIndex = 40;
    const goalRow = rows[goalRowIndex];
    let dailyTarget = 0;
    if (goalRow) {
      dailyTarget = parseCurrency(goalRow[1]);
    }
    if (dailyTarget === 0) dailyTarget = 1;

    // 5. Advisors
    const advisors: AdvisorData[] = [];

    rows.forEach((row, index) => {
      // Skip invalid rows
      if (index === totalRowIndex) return;
      if (index < 1) return; // Header
      if (index >= 35) return; // Footer/Goal area

      const name = row[0]?.trim();
      if (!name || name === 'ASESOR' || name.toUpperCase().includes('TOTAL')) return;

      const orders = parseInteger(row[1]);

      // Calculate advisor total
      // We sum the hourly columns (2-11) for the advisor to get their contribution
      let advisorTotal = 0;
      const hourlySales: number[] = [];
      for (let i = 2; i <= 11; i++) {
        const val = parseCurrency(row[i]);
        hourlySales.push(val);
        advisorTotal += val;
      }

      // Only add if they have activity
      if (orders > 0 || advisorTotal > 0) {
        advisors.push({
            name,
            orders,
            hourlySales,
            totalSales: advisorTotal
        });
      }
    });

    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching dashboard data:', error);
    throw error;
  }
};

