// Declare PapaParse globally since we loaded it via CDN
declare const Papa: any;

// Helper: Delay for retry
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper: Clean currency string to number
// Handles both $1.000,00 and $1,000.00 formats
const parseCurrency = (value: string | undefined): number => {
  if (!value) return 0;
  // Remove currency symbols, spaces, quotes
  const clean = String(value).replace(/['"$]/g, '').trim();
  if (!clean) return 0;

  // Check format heuristic
  const lastCommaIndex = clean.lastIndexOf(',');
  const lastDotIndex = clean.lastIndexOf('.');

  // If comma is after dot (1.234,50), or comma exists but no dot (1234,50)
  if (lastCommaIndex > lastDotIndex) {
     // Remove dots (thousands), replace comma with dot (decimal)
     return parseFloat(clean.replace(/\./g, '').replace(',', '.'));
  }

  // Default/US: 1,234.50 -> Remove commas
  return parseFloat(clean.replace(/,/g, ''));
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  return parseInt(String(value).replace(/\D/g, ''), 10) || 0;
};

// Retry wrapper for fetch
const fetchWithRetry = async (url: string, retries = 3, backoff = 1000): Promise<string> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

    const contentType = response.headers.get("content-type");
    if (contentType && contentType.includes("application/json")) {
        const json = await response.json();
        return json.contents;
    }

    return await response.text();
  } catch (error) {
    if (retries > 0) {
      console.warn(`Fetch failed, retrying in ${backoff}ms...`, error);
      await delay(backoff);
      return fetchWithRetry(url, retries - 1, backoff * 2);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // 1. Fetch CSV Text using Proxy to avoid CORS
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(CONFIG.SHEET_URL)}`;
    const csvText = await fetchWithRetry(proxyUrl);

    // 2. Parse using PapaParse
    // This handles automatic delimiter detection (comma vs semicolon) and quoted strings
    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: true,
    });

    if (parseResult.errors.length > 0) {
      console.warn('PapaParse warnings:', parseResult.errors);
    }

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- LOGIC TO FIND KEY DATA ---

    // 1. Find "TOTAL" Row
    // We search the first column for the word "TOTAL"
    let totalRowIndex = rows.findIndex(r => r[0] && String(r[0]).toUpperCase().includes('TOTAL'));

    // Fallback if not found strictly
    if (totalRowIndex === -1) {
        // Try looking at row 18 (index 17) as default
        if (rows.length > 17) totalRowIndex = 17;
        else throw new Error('Could not find TOTAL row');
    }

    const totalRow = rows[totalRowIndex];

    // 2. Extract Total KPIs
    // Based on structure: Col B (Index 1) = Orders, Col E (Index 4) = Total Amount
    const totalOrders = parseInteger(totalRow[1]);
    let totalSales = parseCurrency(totalRow[4]);

    // 3. Extract Hourly Data for Chart (Columns C to L -> Index 2 to 11)
    const hourlyTotals: number[] = [];
    let sumOfHours = 0;
    for (let i = 2; i <= 11; i++) {
      const val = parseCurrency(totalRow[i]);
      hourlyTotals.push(val);
      sumOfHours += val;
    }

    // Fallback logic: if Column E is empty/zero but we have hourly data, use the sum
    if (totalSales === 0 && sumOfHours > 0) {
        totalSales = sumOfHours;
    }

    // 4. Extract Daily Target (B41)
    // Excel Row 41 -> Index 40. Column B -> Index 1.
    const goalRowIndex = 40;
    let dailyTarget = 0;
    if (rows[goalRowIndex] && rows[goalRowIndex][1]) {
        dailyTarget = parseCurrency(rows[goalRowIndex][1]);
    }
    // Safety fallback
    if (dailyTarget === 0) dailyTarget = 1;

    // 5. Process Advisors
    // Exclude Header (0), Total Row, and Footer areas
    const advisors: AdvisorData[] = [];

    rows.forEach((row, index) => {
       // Skip Header
       if (index === 0) return;
       // Skip Total Row
       if (index === totalRowIndex) return;
       // Skip rows way below data (arbitrary safe buffer, or based on content)
       // If row is empty or name is "ASESOR" or contains "TOTAL" again
       const name = row[0]?.trim();
       if (!name || name === 'ASESOR' || name.toUpperCase().includes('TOTAL')) return;

       // Skip rows after the main data block (often rows > 30 are summary/target tables)
       if (index > 30 && index !== totalRowIndex) return; 

       const orders = parseInteger(row[1]);

       let advisorTotal = 0;
       const hourlySales: number[] = [];
       // Columns 2 to 11
       for (let i = 2; i <= 11; i++) {
         const val = parseCurrency(row[i]);
         hourlySales.push(val);
         advisorTotal += val;
       }

       if (advisorTotal > 0 || orders > 0) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales
         });
       }
    });

    // Sort: Top sales first
    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

