  REFRESH_INTERVAL_MS: 300000, // 5 minutes
};

export const COLORS = {
  BLUE: '#325795',
  RED: '#C8102E',
  GREEN: '#01B693',
  GOLD: '#FFD700',
  GREY: '#F5F5F5',
  DARK_BG: '#151b26', // Slightly lighter than body for cards
  PREMIUM_BG: '#0b0e14', // Deep premium dark
};

export const SOUNDS = {
  CASH_REGISTER: 'https://www.soundjay.com/misc/sounds/cash-register-05.mp3',
  APPLAUSE: 'https://www.soundjay.com/human/sounds/applause-01.mp3'
};

export const HOURS = [
  '10:00', '11:00', '12:00', '13:00', '14:00', 
  '15:00', '16:00', '17:00', '18:00', '19:00'
];

import { CONFIG } from '../constants';
import { DashboardData, AdvisorData } from '../types';

// Declare PapaParse globally since we loaded it via CDN
declare const Papa: any;

// Helper: Delay for retry
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Helper: Clean currency string to number
// Handles: "$ 1.200,00", "1,200.00", "1200"
const parseCurrency = (value: string | undefined): number => {
  if (!value) return 0;
  // Remove currency symbols, spaces, quotes
  const clean = String(value).replace(/['"$a-zA-Z]/g, '').trim();
  if (!clean) return 0;

  // Check format heuristic for thousands separator
  const lastCommaIndex = clean.lastIndexOf(',');
  const lastDotIndex = clean.lastIndexOf('.');

  // Scenario: 1.234,50 (Argentina/Europe) -> Comma is decimal
  if (lastCommaIndex > lastDotIndex) {
     // Remove dots (thousands), replace comma with dot (decimal)
     return parseFloat(clean.replace(/\./g, '').replace(',', '.'));
  }

  // Scenario: 1,234.50 (US) or 1234.50 -> Dot is decimal
  // We just remove commas
  return parseFloat(clean.replace(/,/g, ''));
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  return parseInt(String(value).replace(/\D/g, ''), 10) || 0;
};

// Retry wrapper for fetch
const fetchWithRetry = async (url: string, retries = 3, backoff = 1000): Promise<string> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

    const contentType = response.headers.get("content-type");
    if (contentType && contentType.includes("application/json")) {
        const json = await response.json();
        return json.contents;
    }

    return await response.text();
  } catch (error) {
    if (retries > 0) {
      console.warn(`Fetch failed, retrying in ${backoff}ms...`, error);
      await delay(backoff);
      return fetchWithRetry(url, retries - 1, backoff * 2);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // 1. Prepare URL with Cache Busting
    // We add a random timestamp to ensure the Proxy doesn't return cached data
    const timestamp = new Date().getTime();
    const sheetUrlWithCacheBust = `${CONFIG.SHEET_URL}&t=${timestamp}`;

    // 2. Fetch via Proxy
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(sheetUrlWithCacheBust)}`;
    const csvText = await fetchWithRetry(proxyUrl);

    // 3. Parse using PapaParse
    // CRITICAL: skipEmptyLines must be FALSE to ensure Row 41 is actually index 40
    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: false, 
    });

    if (parseResult.errors.length > 0) {
      console.warn('PapaParse warnings:', parseResult.errors);
    }

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- DATA EXTRACTION ---

    // 1. Find "TOTAL" Row
    // Search column 0 (A) for "TOTAL". 
    // Usually around row 18 (index 17).
    let totalRowIndex = rows.findIndex(r => r[0] && String(r[0]).toUpperCase().includes('TOTAL'));

    // Fallback logic
    if (totalRowIndex === -1) {
        if (rows.length > 17) totalRowIndex = 17; // Default to row 18 (0-indexed 17)
        else throw new Error('Could not find TOTAL row');
    }

    const totalRow = rows[totalRowIndex];

    // Extract Total KPIs
    // Col B (Index 1) = Orders
    // Col E (Index 4) = Total Amount
    const totalOrders = parseInteger(totalRow[1]);
    let totalSales = parseCurrency(totalRow[4]);

    // Hourly Data extraction (Cols C to L -> Index 2 to 11)
    const hourlyTotals: number[] = [];
    let sumOfHours = 0;
    for (let i = 2; i <= 11; i++) {
      const val = parseCurrency(totalRow[i]);
      hourlyTotals.push(val);
      sumOfHours += val;
    }

    // Fallback: If Column E is 0 but hours have data, use sum
    if (totalSales === 0 && sumOfHours > 0) {
        totalSales = sumOfHours;
    }

    // 2. Extract Daily Target from B41
    // Excel Row 41 is Index 40 (since we did NOT skip empty lines).
    // Column B is Index 1.
    const goalRowIndex = 40;
    let dailyTarget = 0;

    if (rows[goalRowIndex]) {
        dailyTarget = parseCurrency(rows[goalRowIndex][1]);
    }

    // Fallback to prevent division by zero
    if (dailyTarget === 0) dailyTarget = 1;

    // 3. Process Advisors
    const advisors: AdvisorData[] = [];

    rows.forEach((row, index) => {
       // Ignore header (0), total row, and anything below the main block
       // We stop processing if we hit the "TOTAL" row or go beyond reasonable advisor list
       if (index === 0) return;
       if (index === totalRowIndex) return;

       // Stop processing if we are deep in the footer area (target calc area)
       if (index >= 35) return; 

       const name = row[0]?.trim();
       // Filter out empty names or structural labels
       if (!name || name === 'ASESOR' || name.toUpperCase().includes('TOTAL')) return;

       const orders = parseInteger(row[1]);

       let advisorTotal = 0;
       const hourlySales: number[] = [];
       // Columns 2 to 11
       for (let i = 2; i <= 11; i++) {
         const val = parseCurrency(row[i]);
         hourlySales.push(val);
         advisorTotal += val;
       }

       // Only include if they have data
       if (advisorTotal > 0 || orders > 0) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales
         });
       }
    });

    // Sort Descending by Sales
    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

