    <script>
        // CONFIGURACIÓN - CAMBIA EL ENLACE AQUÍ
        const SHEET_URL = 'https://docs.google.com/spreadsheets/d/e/2PACX-1vRkCTRPfVd-JDs_ALNrq3JxHsl6hGQR90Vs243vt1iGo8vVhVhnkSvgbC4DQ9R-Vw/pub?gid=584708407&single=true&output=csv';

        let soundEnabled = false;
        let goalReached = false;
        const cashRegisterSound = new Audio('https://www.soundjay.com/misc/sounds/cash-register-05.mp3');

        // Toggle Sonido
        document.getElementById('sound-btn').onclick = () => {
            soundEnabled = !soundEnabled;
            document.getElementById('sound-icon').innerText = soundEnabled ? '🔊' : '🔈';
        };

        const formatMoney = (val) => new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS', maximumFractionDigits: 0 }).format(val);

        let rankingChart, evolutionChart;

        async function updateDashboard() {
            // Cache busting para datos frescos
            const url = `${SHEET_URL}&ts=${new Date().getTime()}`;

            Papa.parse(url, {
                download: true,
                skipEmptyLines: false, // CLAVE: No salta filas para mantener el índice de la fila 41
                complete: function(results) {
                    const data = results.data;

                    // 1. Extraer Totales (Fila 18 -> Índice 17)
                    const rowTotal = data[17];
                    const totalVenta = parseFloat(rowTotal[4].replace(/[^0-9.-]+/g,"")) || 0;
                    const totalPedidos = rowTotal[1] || 0;

                    // 2. Extraer Meta (Fila 41 -> Índice 40, Col B -> Índice 1)
                    const rowMeta = data[40];
                    const montoMeta = rowMeta ? parseFloat(rowMeta[1].replace(/[^0-9.-]+/g,"")) || 1 : 1;

                    // 3. Procesar Asesores (Filas 1 a 16 aprox)
                    let asesoresNames = [];
                    let asesoresValues = [];
                    for(let i=1; i<17; i++) {
                        if(data[i] && data[i][0] && data[i][0] !== "") {
                            asesoresNames.push(data[i][0]);
                            asesoresValues.push(parseFloat(data[i][4]?.replace(/[^0-9.-]+/g,"")) || 0);
                        }
                    }

                    // 4. Procesar Evolución Horaria (Fila 18, Columnas C a M)
                    const horasLabels = ["10:00", "11:00", "12:00", "13:00", "14:00", "15:00", "16:00", "17:00", "18:00", "19:00"];
                    const horasData = rowTotal.slice(2, 12).map(v => parseFloat(v.replace(/[^0-9.-]+/g,"")) || 0);

                    // Actualizar UI
                    document.getElementById('total-venta').innerText = formatMoney(totalVenta);
                    document.getElementById('total-pedidos').innerText = totalPedidos;
                    document.getElementById('meta-valor').innerText = `Meta: ${formatMoney(montoMeta)}`;

                    const porcentaje = Math.round((totalVenta / montoMeta) * 100);
                    document.getElementById('porcentaje-meta').innerText = porcentaje + '%';
                    document.getElementById('update-time').innerText = 'Última actualización: ' + new Date().toLocaleTimeString();

                    // Lógica de Celebración
                    if (totalVenta >= montoMeta && !goalReached) {
                        goalReached = true;
                        document.body.classList.add('celebration-bg');
                        document.getElementById('celebration-modal').classList.remove('hidden');
                        if (soundEnabled) cashRegisterSound.play();
                    }

                    // Actualizar Gráficos
                    updateCharts(asesoresNames, asesoresValues, horasLabels, horasData);
                }
            });
        }

        function updateCharts(aNames, aVals, hLabels, hData) {
            const ctx1 = document.getElementById('rankingChart').getContext('2d');
            const ctx2 = document.getElementById('evolutionChart').getContext('2d');

            if(rankingChart) rankingChart.destroy();
            if(evolutionChart) evolutionChart.destroy();

            rankingChart = new Chart(ctx1, {
                type: 'bar',
                data: {
                    labels: aNames,
                    datasets: [{
                        label: 'Ventas por Asesor',
                        data: aVals,
                        backgroundColor: '#325795',
                        borderRadius: 5
                    }]
                },
                options: { indexAxis: 'y', responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } } }
            });

            evolutionChart = new Chart(ctx2, {
                type: 'line',
                data: {
                    labels: hLabels,
                    datasets: [{
                        label: 'Venta por Hora',
                        data: hData,
                        borderColor: '#C8102E',
                        backgroundColor: 'rgba(200, 16, 46, 0.2)',
                        fill: true,
                        tension: 0.4
                    }]
                },
                options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } } }
            });
        }

        // Ejecutar cada 5 minutos
        setInterval(updateDashboard, 300000);
        updateDashboard();
    </script>
</body>
