export const CONFIG = {
  // Exact URL with GID and output=csv
  SHEET_URL: 'https://docs.google.com/spreadsheets/d/e/2PACX-1vRkCTRPfVd-JDs_ALNrq3JxHsl6hGQR90Vs243vt1iGo8vVhVhnkSvgbC4DQ9R-Vw/pub?gid=584708407&single=true&output=csv',
  REFRESH_INTERVAL_MS: 300000, // 5 minutes
};

export const COLORS = {
  BLUE: '#325795',
  RED: '#C8102E',
  GREEN: '#01B693',
  GOLD: '#FFD700',
  GREY: '#F5F5F5',
  DARK_BG: '#151b26', // Slightly lighter than body for cards
  PREMIUM_BG: '#0b0e14', // Deep premium dark
};

export const SOUNDS = {
  CASH_REGISTER: 'https://www.soundjay.com/misc/sounds/cash-register-05.mp3',
  APPLAUSE: 'https://www.soundjay.com/human/sounds/applause-01.mp3'
};

export const HOURS = [
  '10:00', '11:00', '12:00', '13:00', '14:00', 
  '15:00', '16:00', '17:00', '18:00', '19:00'
];

import { CONFIG } from '../constants';
import { DashboardData, AdvisorData } from '../types';

// Declare PapaParse globally since we loaded it via CDN
declare const Papa: any;

// Helper: Delay for retry
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Robust parser for currency strings handling Argentina/EU (dots as thousands, comma as decimal)
// vs US formats.
const parseCurrency = (value: string | undefined): number => {
  if (!value) return 0;
  // Keep numbers, dots, commas, minus
  const clean = String(value).replace(/[^0-9.,-]/g, '').trim();
  if (!clean) return 0;

  const lastComma = clean.lastIndexOf(',');
  const lastDot = clean.lastIndexOf('.');

  // Scenario: 1.234,50 (Argentina/Europe) -> Comma is decimal separator
  // If comma is after dot, or comma exists and dot doesn't (12,50)
  if (lastComma > lastDot) {
     // Remove dots (thousands), replace comma with dot (decimal)
     return parseFloat(clean.replace(/\./g, '').replace(',', '.'));
  }

  // Scenario: 1,234.50 (US) -> Dot is decimal separator
  if (lastDot > lastComma) {
     return parseFloat(clean.replace(/,/g, ''));
  }

  // Fallback for integers or ambiguous single separator
  // Default to standard float parsing (US style) if unsure, 
  // removing commas as thousands separators.
  return parseFloat(clean.replace(/,/g, ''));
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  return parseInt(String(value).replace(/\D/g, ''), 10) || 0;
};

// Retry wrapper for fetch
const fetchWithRetry = async (url: string, retries = 3, backoff = 1000): Promise<string> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

    // Check if response is JSON (Google sometimes returns JSON if parameters are wrong)
    const contentType = response.headers.get("content-type");
    if (contentType && contentType.includes("application/json")) {
        // If it's JSON from AllOrigins/Proxy, extract contents
        const json = await response.json();
        return json.contents;
    }

    return await response.text();
  } catch (error) {
    if (retries > 0) {
      console.warn(`Fetch failed, retrying in ${backoff}ms...`, error);
      await delay(backoff);
      return fetchWithRetry(url, retries - 1, backoff * 2);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // 1. Prepare URL with Cache Busting
    // We add a random timestamp to ensure the Proxy doesn't return cached data
    const timestamp = new Date().getTime();
    const sheetUrlWithCacheBust = `${CONFIG.SHEET_URL}&t=${timestamp}`;

    // 2. Fetch via Proxy (AllOrigins to bypass CORS on the CSV publish link if needed)
    // Note: Published CSVs usually allow CORS, but proxy is safer for some strict browser configs.
    const proxyUrl = `https://api.allorigins.win/get?url=${encodeURIComponent(sheetUrlWithCacheBust)}`;
    const csvText = await fetchWithRetry(proxyUrl);

    // 3. Parse using PapaParse
    // CRITICAL: skipEmptyLines must be FALSE to ensure Row 41 is actually index 40.
    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: false, 
    });

    if (parseResult.errors.length > 0) {
      console.warn('PapaParse warnings:', parseResult.errors);
    }

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- DATA EXTRACTION WITH FIXED INDICES ---

    // 1. TOTAL ROW: Index 17 (Row 18)
    const totalRow = rows[17];
    if (!totalRow) {
      throw new Error('Could not find Row 18 (Total Row)');
    }

    // Extract Total KPIs
    // Col B (Index 1) = Orders
    // Col E (Index 4) = Total Amount
    const totalOrders = parseInteger(totalRow[1]);
    const totalSales = parseCurrency(totalRow[4]);

    // Hourly Data: Cols C to L (Index 2 to 11)
    const hourlyTotals: number[] = [];
    for (let i = 2; i <= 11; i++) {
      hourlyTotals.push(parseCurrency(totalRow[i]));
    }

    // 2. TARGET (META): Index 40 (Row 41), Col B (Index 1)
    let dailyTarget = 1;
    if (rows[40] && rows[40][1]) {
        dailyTarget = parseCurrency(rows[40][1]);
    }
    if (dailyTarget === 0) dailyTarget = 1;

    // 3. ADVISORS: Rows 2 to 17 (Indices 1 to 16)
    // We iterate the fixed range reserved for advisors.
    const advisors: AdvisorData[] = [];

    // Based on sheet structure, advisors are from row 2 (index 1) to row 17 (index 16).
    // Loop stops before total row (index 17).
    for (let i = 1; i < 17; i++) {
       const row = rows[i];
       if (!row) continue;

       const name = row[0]?.trim();

       // Skip invalid rows
       if (!name || name === 'ASESOR' || name.toUpperCase().includes('TOTAL')) continue;

       const orders = parseInteger(row[1]);
       const advisorTotal = parseCurrency(row[4]); // Col E for advisor total

       const hourlySales: number[] = [];
       // Columns 2 to 11
       for (let h = 2; h <= 11; h++) {
         hourlySales.push(parseCurrency(row[h]));
       }

       // Only add valid data
       if (advisorTotal > 0 || orders > 0 || name.length > 2) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales
         });
       }
    }

    // Sort Descending by Sales
    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

