export const HOURS = [
  '10h', '11h', '12h', '13h', '14h', 
  '15h', '16h', '17h', '18h', '19h'
];

import { CONFIG } from '../constants';
import { DashboardData, AdvisorData } from '../types';

// Declare PapaParse globally since we loaded it via CDN
declare const Papa: any;

// Helper: Delay for retry
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// USER PROVIDED PARSING LOGIC (Exact match to parseN)
const parseCurrency = (value: string | undefined): number => {
  if (!value) return 0;
  // Logic: remove $, remove spaces, remove dots, replace comma with dot
  const cleanStr = String(value)
    .replace(/\$/g, '')
    .replace(/\s/g, '')
    .replace(/\./g, '')
    .replace(',', '.');

  return parseFloat(cleanStr) || 0;
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  return parseInt(String(value).replace(/\D/g, ''), 10) || 0;
};

// Retry wrapper for fetch
const fetchWithRetry = async (url: string, retries = 3, backoff = 1000): Promise<string> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

    // We are using the raw proxy, so we expect text directly
    return await response.text();
  } catch (error) {
    if (retries > 0) {
      console.warn(`Fetch failed, retrying in ${backoff}ms...`, error);
      await delay(backoff);
      return fetchWithRetry(url, retries - 1, backoff * 2);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // 1. Cache Busting & Proxy
    const timestamp = new Date().getTime();
    // Using raw proxy as requested in the user's working HTML script
    const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(CONFIG.SHEET_URL)}&t=${timestamp}`;

    const csvText = await fetchWithRetry(proxyUrl);

    // 2. Parse using PapaParse
    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: false, 
    });

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- DATA EXTRACTION ---

    // 1. DYNAMIC TOTAL ROW DETECTION
    // Find index of the row where first column is "TOTAL" (case insensitive, trimmed)
    const totalRowIndex = rows.findIndex(r => r[0] && String(r[0]).toUpperCase().trim() === "TOTAL");

    if (totalRowIndex === -1) {
        throw new Error("❌ ERROR: NO SE ENCUENTRA LA PALABRA 'TOTAL' EN LA HOJA");
    }

    const totalRow = rows[totalRowIndex];

    // Col B (Index 1) = Orders, Col E (Index 4) = Total Amount
    const totalOrders = parseInteger(totalRow[1]);
    const totalSales = parseCurrency(totalRow[4]);

    // Hourly Data: Slice from index 2 to 12 (Cols C to M) based on user script logic
    const hourlyTotals: number[] = totalRow.slice(2, 12).map((val: string) => parseCurrency(val));

    // 2. TARGET (META): Fixed at Row 41 (Index 40)
    let dailyTarget = 1;
    if (rows[40] && rows[40][1]) {
        dailyTarget = parseCurrency(rows[40][1]);
    }
    if (dailyTarget === 0) dailyTarget = 1;

    // 3. ADVISORS
    // Loop from index 1 up to totalRowIndex
    const advisors: AdvisorData[] = [];

    for (let i = 1; i < totalRowIndex; i++) {
       const row = rows[i];
       if (!row || !row[0]) continue; // Skip if no name

       const name = row[0].trim();
       if (!name) continue;

       const orders = parseInteger(row[1]);
       const advisorTotal = parseCurrency(row[4]); // Col E

       // Just basic validation to ensure it's not an empty row in between
       if (advisorTotal > 0 || orders > 0 || name.length > 2) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales: [] // Not strictly used in bar chart, but part of type
         });
       }
    }

    // Sort by sales descending
    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

