    return await response.text();
  } catch (error) {
    if (retries > 0) {
      console.warn(`Fetch failed, retrying in ${backoff}ms...`, error);
      await delay(backoff);
      return fetchWithRetry(url, retries - 1, backoff * 2);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // 1. Cache Busting & Proxy
    const timestamp = new Date().getTime();
    // Using raw proxy as requested in the user's working HTML script
    const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(CONFIG.SHEET_URL)}&t=${timestamp}`;

    const csvText = await fetchWithRetry(proxyUrl);

    // 2. Parse using PapaParse
    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: false, 
    });

    const rows: string[][] = parseResult.data;

