    // The correct Total Sales is the SUM of all hourly columns extracted above.
    const totalSales = hourlyTotals.reduce((sum, val) => sum + val, 0);

    // 2. TARGET (META): Fixed at Row 41 (Index 40)
    let dailyTarget = 1;
    if (rows[40] && rows[40][1]) {
        dailyTarget = parseCurrency(rows[40][1]);
    }
    if (dailyTarget === 0) dailyTarget = 1;

    // 3. ADVISORS
    // Loop from index 1 up to totalRowIndex
    const advisors: AdvisorData[] = [];

    for (let i = 1; i < totalRowIndex; i++) {
       const row = rows[i];
       if (!row || !row[0]) continue; // Skip if no name

       const name = row[0].trim();
       if (!name) continue;

       const orders = parseInteger(row[1]);

       // Calculate Advisor Total by summing their hourly sales columns (same range as total row)
       const advisorHourlySales = row.slice(2, 12).map((val: string) => parseCurrency(val));
       const advisorTotal = advisorHourlySales.reduce((sum, val) => sum + val, 0);

       // Filter empty rows
       if (advisorTotal > 0 || orders > 0 || name.length > 2) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales: advisorHourlySales
         });
       }
    }

    // Sort by sales descending
    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

import { CONFIG } from '../constants';
import { DashboardData, AdvisorData } from '../types';

// Declare PapaParse globally since we loaded it via CDN
declare const Papa: any;

// Helper: Delay for retry
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Smart parsing to handle mixed locales (US vs AR).
 * US: 1,000.50
 * AR: 1.000,50
 */
const smartParseNumber = (value: string | undefined): number => {
  if (!value) return 0;
  let str = String(value).trim();
  str = str.replace(/[$\s]/g, ''); // Remove $ and spaces

  if (str === '0' || str === '') return 0;

  const lastComma = str.lastIndexOf(',');
  const lastDot = str.lastIndexOf('.');

  // Scenario 1: Both separators present -> High Confidence
  if (lastComma > -1 && lastDot > -1) {
    if (lastDot > lastComma) {
      // US Format (e.g. 1,234.56) -> Remove commas
      return parseFloat(str.replace(/,/g, ''));
    } else {
      // AR Format (e.g. 1.234,56) -> Remove dots, replace comma with dot
      return parseFloat(str.replace(/\./g, '').replace(',', '.'));
    }
  }

  // Scenario 2: Only Dot present
  if (lastDot > -1) {
    const dotCount = (str.match(/\./g) || []).length;
    // Multiple dots = AR Thousands (e.g. 1.000.000)
    if (dotCount > 1) {
      return parseFloat(str.replace(/\./g, ''));
    }
    // Single dot
    // If it ends with .### (3 digits), treat as AR Thousands (e.g. 1.000)
    // If it ends with .## (2 digits) or other, treat as US Decimal (e.g. 10.50)
    if (/\.\d{3}$/.test(str)) {
       return parseFloat(str.replace(/\./g, ''));
    }
    return parseFloat(str);
  }

  // Scenario 3: Only Comma present
  if (lastComma > -1) {
    const commaCount = (str.match(/,/g) || []).length;
    // Multiple commas = US Thousands (e.g. 1,000,000)
    if (commaCount > 1) {
      return parseFloat(str.replace(/,/g, ''));
    }
    // Single comma
    // If it ends with ,### (3 digits), treat as US Thousands (e.g. 1,000)
    // If it ends with ,## (2 digits), treat as AR Decimal (e.g. 10,50)
    if (/,\d{3}$/.test(str)) {
      return parseFloat(str.replace(/,/g, ''));
    }
    return parseFloat(str.replace(',', '.'));
  }

  // No separators
  return parseFloat(str);
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  return parseInt(String(value).replace(/\D/g, ''), 10) || 0;
};

// Retry wrapper for fetch
const fetchWithRetry = async (url: string, retries = 3, backoff = 1000): Promise<string> => {
