      console.warn(`Fetch failed, retrying in ${backoff}ms...`, error);
      await delay(backoff);
      return fetchWithRetry(url, retries - 1, backoff * 2);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // 1. Cache Busting & Proxy
    const timestamp = new Date().getTime();
    const proxyUrl = `https://api.allorigins.win/raw?url=${encodeURIComponent(CONFIG.SHEET_URL)}&t=${timestamp}`;

    const csvText = await fetchWithRetry(proxyUrl);

    // 2. Parse using PapaParse
    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: false, 
    });

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- DATA EXTRACTION ---

    // 1. DYNAMIC TOTAL ROW DETECTION
    const totalRowIndex = rows.findIndex(r => r[0] && String(r[0]).toUpperCase().trim() === "TOTAL");

    if (totalRowIndex === -1) {
        throw new Error("❌ ERROR: NO SE ENCUENTRA LA PALABRA 'TOTAL' EN LA HOJA");
    }

    const totalRow = rows[totalRowIndex];

    // Col B (Index 1) = Orders
    const totalOrders = parseInteger(totalRow[1]);

    // Hourly Data: Summing columns 2 to 12 (10h to 19h)
    const hourlyTotals: number[] = totalRow.slice(2, 12).map((val: string) => smartParseNumber(val));

    // SUM HOURLY TOTALS FOR GRAND TOTAL
    const totalSales = hourlyTotals.reduce((sum, val) => sum + val, 0);

    // 2. TARGET (META): Fixed at Row 41 (Index 40)
    let dailyTarget = 1;
    if (rows[40] && rows[40][1]) {
        dailyTarget = smartParseNumber(rows[40][1]);
    }
    if (dailyTarget === 0) dailyTarget = 1;

    // 3. ADVISORS
    const advisors: AdvisorData[] = [];

    for (let i = 1; i < totalRowIndex; i++) {
       const row = rows[i];
       if (!row || !row[0]) continue; // Skip if no name

       const name = row[0].trim();
       if (!name) continue;

       const orders = parseInteger(row[1]);

       const advisorHourlySales = row.slice(2, 12).map((val: string) => smartParseNumber(val));
       const advisorTotal = advisorHourlySales.reduce((sum, val) => sum + val, 0);

       if (advisorTotal > 0 || orders > 0 || name.length > 2) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales: advisorHourlySales
         });
       }
    }

    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

