    const totalRow = rows[totalRowIndex];

    // Col B (Index 1) = Orders
    const totalOrders = parseInteger(totalRow[1]);

    // Hourly Data: Parsing columns 2 to 12 (10h to 19h)
    const hourlyTotals: number[] = totalRow.slice(2, 12).map((val: string) => smartParseNumber(val));

    // CORRECTION: Data is CUMULATIVE (Running Total). 
    // Do NOT sum the columns. The Total is simply the highest value reached (the latest populated cumulative column).
    const totalSales = Math.max(...hourlyTotals);

    // 2. TARGET (META): Fixed at Row 41 (Index 40)
    let dailyTarget = 1;
    if (rows[40] && rows[40][1]) {
        dailyTarget = smartParseNumber(rows[40][1]);
    }
    if (dailyTarget === 0) dailyTarget = 1;

    // 3. ADVISORS
    const advisors: AdvisorData[] = [];

    for (let i = 1; i < totalRowIndex; i++) {
       const row = rows[i];
       if (!row || !row[0]) continue; // Skip if no name

       const name = row[0].trim();
       if (!name) continue;

       const orders = parseInteger(row[1]);

       const advisorHourlySales = row.slice(2, 12).map((val: string) => smartParseNumber(val));
       // CORRECTION: Data is CUMULATIVE. Use Max instead of Sum.
       const advisorTotal = Math.max(...advisorHourlySales);

       if (advisorTotal > 0 || orders > 0 || name.length > 2) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales: advisorHourlySales
         });
       }
    }

    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

