const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('es-AR', {
    style: 'currency',
    currency: 'ARS',
    minimumFractionDigits: 0, // Removed decimals for cleaner look on large numbers
    maximumFractionDigits: 0,
  }).format(value);
};

const App: React.FC = () => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [lastRefresh, setLastRefresh] = useState<Date>(new Date());

  // Celebration State
  const [celebrationMode, setCelebrationMode] = useState<boolean>(false);
  const [audioEnabled, setAudioEnabled] = useState<boolean>(false);
  const hasCelebratedRef = useRef<boolean>(false);

  const loadData = useCallback(async () => {
    try {
      setError(null);
      const dashboardData = await fetchDashboardData();
      setData(dashboardData);
      setLastRefresh(new Date());

      // Check Celebration Condition
      if (dashboardData.totalSales >= dashboardData.dailyTarget && dashboardData.totalSales > 0 && dashboardData.dailyTarget > 1) {
        setCelebrationMode(true);
      } else {
        setCelebrationMode(false);
        hasCelebratedRef.current = false; 
      }

    } catch (err) {
      console.error(err);
      setError('⚠️ Reintentando...');
    } finally {
      setLoading(false);
    }
  }, []);

  // Audio Effect Logic
  useEffect(() => {
    if (celebrationMode && !hasCelebratedRef.current && audioEnabled) {
      const playSequence = async () => {
        try {
          const register = new Audio(SOUNDS.CASH_REGISTER);
          await register.play();
          hasCelebratedRef.current = true;
        } catch (e) {
          console.warn("Autoplay prevented", e);
        }
      };
      playSequence();
    }
  }, [celebrationMode, audioEnabled]);

  useEffect(() => {
    loadData();
    const intervalId = setInterval(loadData, CONFIG.REFRESH_INTERVAL_MS);
    return () => clearInterval(intervalId);
  }, [loadData]);

  const toggleAudio = () => {
    setAudioEnabled(!audioEnabled);
  };

  if (loading && !data) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-[#0b0e14] text-white">
        <div className="flex flex-col items-center gap-4">
           {/* Initial connection state */}
           <p className="text-[#325795] font-mono text-sm uppercase font-bold animate-pulse">Conectando con Google Sheets...</p>
        </div>
      </div>
    );
  }

  const totalSales = data?.totalSales || 0;
  const totalOrders = data?.totalOrders || 0;
  const target = data?.dailyTarget || 1;
  const progress = totalSales / target;

  return (
    <div className={`h-screen w-screen flex flex-col p-6 transition-all duration-1000 ease-in-out font-sans overflow-hidden
        ${celebrationMode 
          ? 'bg-gradient-to-l from-[#C8102E] via-[#325795] to-[#01B693] bg-[length:400%_400%] animate-[gradientAnim_8s_ease_infinite]' 
          : 'bg-[#0b0e14]'
        }`}>

        <style>{`
          @keyframes gradientAnim {
              0%{background-position:0% 50%}
              50%{background-position:100% 50%}
              100%{background-position:0% 50%}
          }
        `}</style>

      {/* Header - Compact */}
      <div className="flex justify-between items-center mb-4 z-10 shrink-0">
        <div>
