import React from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  ChartOptions,
  Filler 
} from 'chart.js';
import { Bar, Line } from 'react-chartjs-2';
import { COLORS, HOURS } from '../constants';
import { AdvisorData } from '../types';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const commonOptions: ChartOptions<any> = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: { display: false },
    title: { display: false },
    tooltip: {
      backgroundColor: 'rgba(0, 0, 0, 0.9)', // Darker tooltip
      titleColor: '#fff',
      bodyColor: '#e5e7eb',
      borderColor: 'rgba(255,255,255,0.2)',
      borderWidth: 1,
      padding: 10,
      displayColors: false,
      titleFont: { size: 13 },
      bodyFont: { size: 13 }
    },
  },
  scales: {
    x: {
      grid: { display: false },
      ticks: { color: '#9CA3AF', font: { size: 10, weight: '600' } } 
    },
    y: {
      grid: { color: 'rgba(255,255,255,0.05)' }, 
      ticks: { 
        color: '#9CA3AF',
        font: { size: 9 },
        callback: (value: any) => {
             if (value >= 1000000) return '$' + (value / 1000000).toFixed(1) + 'M';
             if (value >= 1000) return '$' + (value / 1000).toFixed(0) + 'k';
             return '$' + value;
        }
      }
    }
  }
};

interface AdvisorBarChartProps {
  advisors: AdvisorData[];
}

export const AdvisorBarChart: React.FC<AdvisorBarChartProps> = ({ advisors }) => {
  const dataToRender = advisors;

  const data = {
    labels: dataToRender.map(a => a.name.split(' ')[0]),
    datasets: [
      {
        data: dataToRender.map(a => a.totalSales),
        backgroundColor: COLORS.BLUE,
        borderRadius: 3,
        barPercentage: 0.7, // Thinner bars to fit more items
        categoryPercentage: 0.9,
        hoverBackgroundColor: '#4f76ba'
      },
    ],
  };

  const options: ChartOptions<'bar'> = {
    ...commonOptions,
    indexAxis: 'y' as const,
    scales: {
       x: { 
         ...commonOptions.scales?.y, 
         grid: { display: false },
         position: 'top' as const // Move value axis to top for cleaner look
       },
       y: { 
         ...commonOptions.scales?.x, 
         grid: { display: false },
         ticks: { 
           color: '#E5E7EB', 
           font: { size: 10, weight: '700' }, // Bold names
           autoSkip: false
         } 
       }
    }
  };

  return <Bar data={data} options={options} />;
};

interface EvolutionLineChartProps {
  hourlyTotals: number[];
}

export const EvolutionLineChart: React.FC<EvolutionLineChartProps> = ({ hourlyTotals }) => {
  const data = {
    labels: HOURS,
    datasets: [
      {
        data: hourlyTotals,
        borderColor: COLORS.RED,
        backgroundColor: 'rgba(200, 16, 46, 0.1)', 
        fill: true,
        tension: 0.4,
        pointRadius: 4,
        pointBackgroundColor: COLORS.RED,
        pointBorderColor: '#fff',
        pointBorderWidth: 2,
        borderWidth: 2
      },
    ],
  };

  const options: ChartOptions<'line'> = {
    ...commonOptions,
  };

  return <Line data={data} options={options} />;
};

