import React, { useEffect, useState, useCallback, useRef } from 'react';
import { fetchDashboardData } from './services/sheetService';
import { DashboardData } from './types';
import { KpiCard } from './components/KpiCard';
import { TopPerformerCard } from './components/TopPerformerCard';
import { HourlyBlock } from './components/HourlyBlock';
import { AdvisorBarChart, EvolutionLineChart } from './components/Charts';
import { COLORS, CONFIG, SOUNDS, HOURS } from './constants';

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('es-AR', {
    style: 'currency',
    currency: 'ARS',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const App: React.FC = () => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [lastRefresh, setLastRefresh] = useState<Date>(new Date());

  // Celebration State
  const [celebrationMode, setCelebrationMode] = useState<boolean>(false);
  const [audioEnabled, setAudioEnabled] = useState<boolean>(false);
  const hasCelebratedRef = useRef<boolean>(false);

  const loadData = useCallback(async () => {
    try {
      setError(null);
      const dashboardData = await fetchDashboardData();
      setData(dashboardData);
      setLastRefresh(new Date());

      // Check Celebration Condition
      if (dashboardData.totalSales >= dashboardData.dailyTarget && dashboardData.totalSales > 0 && dashboardData.dailyTarget > 1) {
        setCelebrationMode(true);
      } else {
        setCelebrationMode(false);
        hasCelebratedRef.current = false; 
      }

    } catch (err) {
      console.error(err);
      setError('⚠️ Reintentando...');
    } finally {
      setLoading(false);
    }
  }, []);

  // Audio Effect Logic
  useEffect(() => {
    if (celebrationMode && !hasCelebratedRef.current && audioEnabled) {
      const playSequence = async () => {
        try {
          const register = new Audio(SOUNDS.CASH_REGISTER);
          await register.play();
          hasCelebratedRef.current = true;
        } catch (e) {
          console.warn("Autoplay prevented", e);
        }
      };
      playSequence();
    }
  }, [celebrationMode, audioEnabled]);

  useEffect(() => {
    loadData();
    const intervalId = setInterval(loadData, CONFIG.REFRESH_INTERVAL_MS);
    return () => clearInterval(intervalId);
  }, [loadData]);

  const toggleAudio = () => {
    setAudioEnabled(!audioEnabled);
  };

  if (loading && !data) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-[#0b0e14] text-white">
        <div className="flex flex-col items-center gap-4">
           <p className="text-[#325795] font-mono text-sm uppercase font-bold animate-pulse">Conectando con Google Sheets...</p>
        </div>
      </div>
    );
  }

  const totalSales = data?.totalSales || 0;
  const totalOrders = data?.totalOrders || 0;
  const target = data?.dailyTarget || 1;
  const progress = totalSales / target;
  const topPerformer = data?.advisors[0]; // Advisors are already sorted by sales

  return (
    <div className={`h-screen w-screen flex flex-col p-4 md:p-6 transition-all duration-1000 ease-in-out font-sans overflow-hidden
        ${celebrationMode 
          ? 'bg-gradient-to-l from-[#C8102E] via-[#325795] to-[#01B693] bg-[length:400%_400%] animate-[gradientAnim_8s_ease_infinite]' 
          : 'bg-[#0b0e14]'
        }`}>

        <style>{`
          @keyframes gradientAnim {
              0%{background-position:0% 50%}
              50%{background-position:100% 50%}
              100%{background-position:0% 50%}
          }
        `}</style>

      {/* Header */}
      <div className="flex justify-between items-center mb-4 shrink-0">
        <div>
            <h1 className="text-2xl md:text-3xl font-black uppercase tracking-tighter text-white drop-shadow-md">Dashboard de Ventas</h1>
            <div className="flex items-center gap-2 mt-1">
              <div className={`w-2 h-2 rounded-full ${error ? 'bg-yellow-500' : 'bg-green-500 animate-pulse'}`}></div>
              <p className="text-[10px] text-gray-400 font-mono">
                Última actualización: <span className="text-white">{lastRefresh.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit', second: '2-digit'})}</span>
              </p>
            </div>
        </div>
        <div className="flex items-center gap-4">
            <button 
                onClick={toggleAudio}
                className={`hidden md:block px-3 py-1.5 rounded-lg border text-[10px] font-bold transition-all hover:bg-black/60 shadow-lg backdrop-blur-sm
                  ${audioEnabled 
                    ? 'bg-black/50 border-green-500/50 text-green-400' 
                    : 'bg-black/50 border-white/10 text-gray-400'
                  }`}>
                {audioEnabled ? 'SONIDO ACTIVO' : 'SILENCIO'}
            </button>
            <div className="bg-white/5 p-2 rounded-lg backdrop-blur-sm border border-white/10">
              <img 
                src="https://ugc.production.linktr.ee/5ef65f71-15a5-4bc2-8e40-71e49e3483e5_FarmaPlus-ORIGINAL-H.png" 
                alt="Logo" 
                className="h-6 object-contain opacity-90"
              />
            </div>
        </div>
      </div>

      {/* ROW 1: KPIs + Top Performer */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-4 shrink-0">
        <KpiCard
          title="Facturación Total"
          value={formatCurrency(totalSales)}
          color={COLORS.BLUE}
        />
        <KpiCard
          title="Pedidos"
          value={totalOrders.toString()}
          color={COLORS.RED}
        />
        <KpiCard
          title="% Cumplimiento"
          value={`${Math.round(progress * 100)}%`}
          color={COLORS.GREEN}
          percentage={progress}
        />
        <TopPerformerCard 
          advisor={topPerformer} 
          totalSales={totalSales} 
        />
      </div>

      {/* ROW 2: Hourly Blocks */}
      <div className="flex gap-2 md:gap-3 mb-4 shrink-0 overflow-x-auto pb-1 scrollbar-hide">
        {HOURS.map((hour, index) => (
          <HourlyBlock 
            key={hour} 
            hour={hour} 
            value={data?.hourlyTotals[index] || 0}
          />
        ))}
      </div>

      {/* ROW 3: Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 flex-1 min-h-0 overflow-hidden">

        {/* Advisor Ranking */}
        <div className="bg-[#0f131a] p-5 rounded-2xl border border-white/5 flex flex-col shadow-xl">
            <div className="flex justify-between items-center mb-2">
                 <h3 className="text-gray-200 font-bold text-sm tracking-wide">Ranking de Asesores (al corte)</h3>
            </div>
            <div className="flex-1 min-h-0 relative">
                 {data && <AdvisorBarChart advisors={data.advisors} />}
            </div>
        </div>

        {/* Evolution Chart */}
        <div className="bg-[#0f131a] p-5 rounded-2xl border border-white/5 flex flex-col shadow-xl">
             <div className="flex justify-between items-center mb-2">
                 <h3 className="text-gray-200 font-bold text-sm tracking-wide">Evolución Horaria</h3>
            </div>
             <div className="flex-1 min-h-0 relative">
                {data && <EvolutionLineChart hourlyTotals={data.hourlyTotals} />}
            </div>
        </div>
      </div>

    </div>
  );
};

export default App;

