import React from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  ChartOptions,
  Filler 
} from 'chart.js';
import { Line } from 'react-chartjs-2';
import { COLORS, HOURS } from '../constants';
import { AdvisorData } from '../types';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const commonOptions: ChartOptions<any> = {
  responsive: true,
  maintainAspectRatio: false,
  plugins: {
    legend: { display: false },
    title: { display: false },
    tooltip: {
      backgroundColor: 'rgba(0, 0, 0, 0.9)', 
      titleColor: '#fff',
      bodyColor: '#e5e7eb',
      borderColor: 'rgba(255,255,255,0.2)',
      borderWidth: 1,
      padding: 10,
      displayColors: false,
      titleFont: { size: 13 },
      bodyFont: { size: 13 }
    },
  },
  scales: {
    x: {
      grid: { display: false },
      ticks: { color: '#9CA3AF', font: { size: 10, weight: '600' } } 
    },
    y: {
      grid: { color: 'rgba(255,255,255,0.05)' }, 
      ticks: { 
        color: '#9CA3AF',
        font: { size: 9 },
        callback: (value: any) => {
             if (value >= 1000000) return '$' + (value / 1000000).toFixed(1) + 'M';
             if (value >= 1000) return '$' + (value / 1000).toFixed(0) + 'k';
             return '$' + value;
        }
      }
    }
  }
};

interface AdvisorBarChartProps {
  advisors: AdvisorData[];
}

export const AdvisorBarChart: React.FC<AdvisorBarChartProps> = ({ advisors }) => {
  // Calculate total sales to determine the share percentage
  const totalSalesAll = advisors.reduce((sum, adv) => sum + adv.totalSales, 0);

  // Find the maximum sales to determine the relative width of the bars (Top 1 = 100% width)
  const maxSales = advisors.length > 0 ? advisors[0].totalSales : 0;

  return (
    <div className="flex flex-col gap-5 h-full overflow-y-auto pr-2 custom-scrollbar pb-2">
       <style>{`
          .custom-scrollbar::-webkit-scrollbar { width: 4px; }
          .custom-scrollbar::-webkit-scrollbar-track { background: rgba(255,255,255,0.02); }
          .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 2px; }
          .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
       `}</style>

       {advisors.map((advisor, index) => {
          const widthPercentage = maxSales > 0 ? (advisor.totalSales / maxSales) * 100 : 0;
          const sharePercentage = totalSalesAll > 0 ? (advisor.totalSales / totalSalesAll) * 100 : 0;

          return (
            <div key={advisor.name} className="flex flex-col w-full group">
                {/* Text Info Row */}
                <div className="flex justify-between items-end mb-2 px-1">

                    {/* Left: Rank & Name */}
                    <div className="flex items-center gap-4">
                         <span className="text-gray-500 font-bold text-lg md:text-xl w-6 text-center">{index + 1}</span>
                         <span className="text-white font-bold text-lg md:text-xl uppercase tracking-wider truncate drop-shadow-md">
                             {advisor.name}
                         </span>
                    </div>

                    {/* Right: Value & Percentage */}
                    <div className="flex items-end gap-4 text-right">
                        <span className="text-white font-bold text-lg md:text-xl font-mono tracking-tight drop-shadow-md">
                            {new Intl.NumberFormat('es-AR', { 
                                style: 'currency', 
                                currency: 'ARS', 
                                maximumFractionDigits: 0 
                            }).format(advisor.totalSales)}
                        </span>
                        <span className="text-gray-500 text-sm font-bold w-12 mb-1">
                            {sharePercentage.toFixed(1)}%
                        </span>
                    </div>
                </div>

                {/* Progress Bar Row */}
                <div className="w-full h-3 bg-[#1e293b]/60 rounded-full overflow-hidden relative shadow-inner border border-white/5">
                     <div 
                        className="h-full rounded-full relative transition-all duration-1000 ease-out flex items-center justify-end"
                        style={{ 
                            width: `${widthPercentage}%`,
                            background: `linear-gradient(90deg, ${COLORS.BLUE} 0%, ${COLORS.GREEN} 100%)`
                        }}
                     >
                        {/* Glow Tip */}
                        <div className="h-full w-2 bg-white/40 blur-[2px] rounded-full mr-[-1px]"></div>
                     </div>
                </div>
            </div>
          );
       })}
    </div>
  );
};

interface EvolutionLineChartProps {
  hourlyTotals: number[];
}

export const EvolutionLineChart: React.FC<EvolutionLineChartProps> = ({ hourlyTotals }) => {
  const data = {
    labels: HOURS,
    datasets: [
      {
        data: hourlyTotals,
        borderColor: COLORS.RED,
        backgroundColor: 'rgba(200, 16, 46, 0.15)', // Slightly more opaque
        fill: true,
        tension: 0.4,
        pointRadius: 6, // Larger points
        pointBackgroundColor: COLORS.RED,
        pointBorderColor: '#fff',
        pointBorderWidth: 2,
        borderWidth: 3,
        hoverRadius: 8
      },
    ],
  };

  const options: ChartOptions<'line'> = {
    ...commonOptions,
    scales: {
        ...commonOptions.scales,
        x: {
            ...commonOptions.scales?.x,
            grid: { display: true, color: 'rgba(255,255,255,0.03)' } // Subtle grid for X
        }
    }
  };

  return <Line data={data} options={options} />;
};

