  // Find the maximum sales to determine the relative width of the bars (Top 1 = 100% width)
  const maxSales = advisors.length > 0 ? advisors[0].totalSales : 0;

  // Duplicate the list for seamless infinite scrolling
  const displayAdvisors = [...advisors, ...advisors];

  // Auto-scroll logic
  const scrollRef = useRef<HTMLDivElement>(null);
  const [isPaused, setIsPaused] = useState(false);

  useEffect(() => {
    const scrollContainer = scrollRef.current;
    if (!scrollContainer) return;

    let animationFrameId: number;
    // Slower speed for better readability (was 0.5)
    let scrollSpeed = 0.25; 

    const animateScroll = () => {
      if (!isPaused && scrollContainer) {
        // If content is scrollable
        if (scrollContainer.scrollHeight > scrollContainer.clientHeight) {
          scrollContainer.scrollTop += scrollSpeed;

          // Infinite Loop Logic:
          // When we have scrolled past the first set (half the total height),
          // reset immediately to 0. Since the second set is identical to the first,
          // this reset is visually invisible.
          if (scrollContainer.scrollTop >= scrollContainer.scrollHeight / 2) {
             scrollContainer.scrollTop = 0;
          }
        }
      }
      animationFrameId = requestAnimationFrame(animateScroll);
    };

    animationFrameId = requestAnimationFrame(animateScroll);

    return () => cancelAnimationFrame(animationFrameId);
  }, [isPaused, advisors]);

  // Helper to generate trend icons
  const getTrendIcons = (hourlySales: number[]) => {
    const icons: React.ReactNode[] = [];

    // Find the index of the last non-zero value to stop rendering future hours
    // But since it's cumulative, finding the last change or last value > 0 is enough.
    // We iterate through all hours available.

    // Safety check: Ensure we don't go out of bounds if array is short
    const limit = Math.min(hourlySales.length, 10); 

    for (let i = 1; i < limit; i++) {
      const current = hourlySales[i];
      const prev = hourlySales[i-1];

      // Optimization: Stop processing if we hit a string of zeros at the end (future hours)
      // Check if current is 0 and all subsequent are 0 (simplified: just check current for now 
      // but strictly we should check if we've reached "now"). 
      // However, simplified logic: if current is 0 and prev was 0, skip.
      if (current === 0 && prev === 0) continue;

      if (current > prev) {
        icons.push(<span key={i} className="text-[10px] 2xl:text-xs mx-[1px]">⬆️</span>);
      } else if (current === prev) {
        // Only show equal if they had started selling previously (prev > 0)
        // This avoids a row of equals signs at 10am/11am if they start at 1pm.
        if (prev > 0) {
           icons.push(<span key={i} className="text-[10px] 2xl:text-xs mx-[1px] opacity-60 grayscale">🟰</span>);
        }
      }
    }
    return icons;
  };

  return (
