interface AdvisorBarChartProps {
  advisors: AdvisorData[];
}

export const AdvisorBarChart: React.FC<AdvisorBarChartProps> = ({ advisors }) => {
  // Calculate total sales to determine the share percentage
  const totalSalesAll = advisors.reduce((sum, adv) => sum + adv.totalSales, 0);

  // Find the maximum sales to determine the relative width of the bars (Top 1 = 100% width)
  const maxSales = advisors.length > 0 ? advisors[0].totalSales : 0;

  // --- SCROLL PREPARATION ---
  // 1. Create a base sequence that is long enough to look good (at least 15 items)
  let baseSequence = [...advisors];
  // Safety break to prevent infinite loop if advisors is empty
  if (baseSequence.length > 0) {
      while (baseSequence.length < 15) {
          baseSequence = [...baseSequence, ...advisors];
      }
  }

  // 2. Double the sequence to create the seamless loop buffer (Part A + Part B)
  // When we scroll past Part A, we jump instantly to start of Part A (which looks like start of Part B)
  const displayAdvisors = [...baseSequence, ...baseSequence];

  // Auto-scroll logic variables
  const scrollRef = useRef<HTMLDivElement>(null);
  const scrollAccumulator = useRef(0); // High precision accumulator for smooth scroll
  const [isPaused, setIsPaused] = useState(false);

  useEffect(() => {
    const scrollContainer = scrollRef.current;
    if (!scrollContainer) return;

    // Sync accumulator with current DOM position on mount/resume
    scrollAccumulator.current = scrollContainer.scrollTop;

    let animationFrameId: number;
    const scrollSpeed = 0.6; // Adjusted for visibility (px per frame)

    const animateScroll = () => {
      if (!isPaused && scrollContainer) {
        // Only scroll if content overflows
        if (scrollContainer.scrollHeight > scrollContainer.clientHeight) {
          scrollAccumulator.current += scrollSpeed;

          // Infinite Loop Logic:
          // Check if we have scrolled past half the content (the first full copy)
          if (scrollAccumulator.current >= scrollContainer.scrollHeight / 2) {
             // Reset to 0 (top) instantly. 
             // Because Part B is identical to Part A, this jump is invisible.
             scrollAccumulator.current = 0;
          }

          scrollContainer.scrollTop = scrollAccumulator.current;
        }
      }
      animationFrameId = requestAnimationFrame(animateScroll);
    };

    animationFrameId = requestAnimationFrame(animateScroll);

    return () => cancelAnimationFrame(animationFrameId);
  }, [isPaused, displayAdvisors]); // Re-run if data changes

  // Helper to generate trend icons
  const getTrendIcons = (hourlySales: number[]) => {
    const icons: React.ReactNode[] = [];
    const limit = Math.min(hourlySales.length, 10); 

    for (let i = 1; i < limit; i++) {
      const current = hourlySales[i];
      const prev = hourlySales[i-1];

      if (current === 0 && prev === 0) continue; 
      if (current === 0 && prev > 0) break; // Stop at "future"

      if (current > prev) {
        icons.push(<span key={i} className="text-sm md:text-base mx-[1px]">⬆️</span>);
      } else if (current === prev) {
        if (prev > 0) {
           icons.push(<span key={i} className="text-sm md:text-base mx-[1px] opacity-60 grayscale">🟰</span>);
        }
      }
    }
    return icons;
  };

  return (
    <div 
      ref={scrollRef}
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
      className="flex flex-col gap-2 2xl:gap-3 h-full overflow-y-auto pr-2 custom-scrollbar pb-2 relative"
    >
       <style>{`
          .custom-scrollbar::-webkit-scrollbar { width: 4px; }
          .custom-scrollbar::-webkit-scrollbar-track { background: rgba(255,255,255,0.02); }
          .custom-scrollbar::-webkit-scrollbar-thumb { background: #334155; border-radius: 2px; }
          .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #475569; }
       `}</style>

       {displayAdvisors.map((advisor, index) => {
          const uniqueKey = `${advisor.name}-${index}`;
          const widthPercentage = maxSales > 0 ? (advisor.totalSales / maxSales) * 100 : 0;
          const sharePercentage = totalSalesAll > 0 ? (advisor.totalSales / totalSalesAll) * 100 : 0;

          // Original rank calculation based on the source data length
          const rank = (index % advisors.length) + 1;

          return (
            <div key={uniqueKey} className="flex flex-col w-full group shrink-0">
                {/* Text Info Row */}
                <div className="flex justify-between items-end mb-1 px-1">

                    {/* Left: Rank & Name & Trend */}
                    <div className="flex items-center gap-2 overflow-hidden mr-2">
                         <span className="text-gray-500 font-bold text-base md:text-lg w-5 text-center shrink-0">{rank}</span>
                         <div className="flex items-center gap-2 min-w-0">
                             <span className="text-white font-bold text-sm md:text-base 2xl:text-lg uppercase tracking-wider truncate drop-shadow-md">
                                 {advisor.name}
                             </span>
                             {/* Trend Icons */}
                             <div className="flex items-center shrink-0 select-none ml-1">
                                {getTrendIcons(advisor.hourlySales)}
                             </div>
                         </div>
                    </div>

                    {/* Right: Value & Percentage */}
                    <div className="flex items-end gap-3 text-right shrink-0">
                        <span className="text-white font-bold text-sm md:text-base 2xl:text-lg font-mono tracking-tight drop-shadow-md">
                            {new Intl.NumberFormat('es-AR', { 
                                style: 'currency', 
                                currency: 'ARS', 
                                maximumFractionDigits: 0 
                            }).format(advisor.totalSales)}
                        </span>
                        <span className="text-gray-500 text-xs 2xl:text-sm font-bold w-10 mb-0.5">
                            {sharePercentage.toFixed(1)}%
                        </span>
                    </div>
                </div>

                {/* Progress Bar Row */}
                <div className="w-full h-2 2xl:h-3 bg-[#1e293b]/60 rounded-full overflow-hidden relative shadow-inner border border-white/5">
                     <div 
                        className="h-full rounded-full relative transition-all duration-1000 ease-out flex items-center justify-end"
                        style={{ 
                            width: `${widthPercentage}%`,
                            background: `linear-gradient(90deg, ${COLORS.BLUE} 0%, ${COLORS.GREEN} 100%)`
                        }}
                     >
                        <div className="h-full w-2 bg-white/40 blur-[2px] rounded-full mr-[-1px]"></div>
                     </div>
                </div>
            </div>
          );
       })}
    </div>
  );
};

