// Create a shared AudioContext
// We use a lazy initialization pattern because AudioContext is not allowed to start without user interaction
let audioCtx: AudioContext | null = null;

const getAudioContext = () => {
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
  }
  return audioCtx;
};

export const initAudio = () => {
  const ctx = getAudioContext();
  if (ctx.state === 'suspended') {
    ctx.resume().catch(e => console.error("Could not resume audio context", e));
  }
};

export const playNotificationSound = () => {
  try {
    const ctx = getAudioContext();
    initAudio();

    const osc = ctx.createOscillator();
    const gainNode = ctx.createGain();

    osc.connect(gainNode);
    gainNode.connect(ctx.destination);

    // Modern "Glass" Ding
    // High pitched sine wave with clean decay
    osc.type = 'sine';
    const now = ctx.currentTime;

    // Frequency sweep for a "bell" effect
    osc.frequency.setValueAtTime(980, now); 
    osc.frequency.exponentialRampToValueAtTime(880, now + 0.1);

    // Volume envelope
    gainNode.gain.setValueAtTime(0.15, now);
    gainNode.gain.exponentialRampToValueAtTime(0.001, now + 0.8);

    osc.start(now);
    osc.stop(now + 0.8);
  } catch (e) {
    console.error("Error generating sound", e);
  }
};

export const playCelebrationSound = () => {
  try {
    const ctx = getAudioContext();
    initAudio();

    const now = ctx.currentTime;
    const notes = [523.25, 659.25, 783.99, 1046.50]; // C Major Arpeggio (C5, E5, G5, C6)

    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.connect(gain);
      gain.connect(ctx.destination);

      const startTime = now + (i * 0.1);

      osc.type = 'triangle'; // Slightly richer tone
      osc.frequency.setValueAtTime(freq, startTime);

      gain.gain.setValueAtTime(0.1, startTime);
      gain.gain.exponentialRampToValueAtTime(0.001, startTime + 0.4);

      osc.start(startTime);
      osc.stop(startTime + 0.4);
    });

  } catch (e) {
    console.error("Error generating celebration sound", e);
  }
};

