      result = parseFloat(cleanStrForDetection.replace(/\./g, '').replace(',', '.'));
    }
  }
  // Scenario 2: Only Dot
  else if (lastDot > -1) {
    const dotCount = (cleanStrForDetection.match(/\./g) || []).length;
    if (dotCount > 1) {
      // 1.000.000 -> 1000000
      result = parseFloat(cleanStrForDetection.replace(/\./g, ''));
    } else if (/\.\d{3}$/.test(cleanStrForDetection)) {
       // 1.000 -> 1000 (Thousands)
       result = parseFloat(cleanStrForDetection.replace(/\./g, ''));
    } else {
       // 10.50 -> 10.5 (Decimal)
       result = parseFloat(cleanStrForDetection);
    }
  }
  // Scenario 3: Only Comma
  else if (lastComma > -1) {
    const commaCount = (cleanStrForDetection.match(/,/g) || []).length;
    if (commaCount > 1) {
      // 1,000,000 -> 1000000
      result = parseFloat(cleanStrForDetection.replace(/,/g, ''));
    } else if (/,\d{3}$/.test(cleanStrForDetection)) {
      // 1,000 -> 1000
      result = parseFloat(cleanStrForDetection.replace(/,/g, ''));
    } else {
      // 10,50 -> 10.5
      result = parseFloat(cleanStrForDetection.replace(',', '.'));
    }
  }
  // No separators
  else {
    result = parseFloat(cleanStrForDetection);
  }

  // Final safety check: if result is NaN, return 0
  return isNaN(result) ? 0 : result;
};

const parseInteger = (value: string | undefined): number => {
  if (!value) return 0;
  const parsed = parseInt(String(value).replace(/\D/g, ''), 10);
  return isNaN(parsed) ? 0 : parsed;
};

// Retry wrapper for fetch with PROXY FALLBACK
const fetchWithRetry = async (url: string, retries = 3, backoff = 1000, useFallback = false): Promise<string> => {
  try {
    const targetUrl = useFallback 
        ? `https://corsproxy.io/?${encodeURIComponent(CONFIG.SHEET_URL)}`
        : `https://api.allorigins.win/raw?url=${encodeURIComponent(CONFIG.SHEET_URL)}&t=${new Date().getTime()}`;

    const response = await fetch(targetUrl);

    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return await response.text();

  } catch (error) {
    console.warn(`Fetch attempt failed (Fallback: ${useFallback})`, error);

    if (retries > 0) {
      await delay(backoff);
      // Switch to fallback proxy on retry if first attempts fail
      const nextUseFallback = retries <= 2 ? true : useFallback; 
      return fetchWithRetry(url, retries - 1, backoff * 1.5, nextUseFallback);
    }
    throw error;
  }
};

export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    // 1. Fetch CSV with Retry and Fallback Proxy Logic built-in
    const csvText = await fetchWithRetry(CONFIG.SHEET_URL);

    // 2. Parse using PapaParse
    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: false, 
    });

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- DATA EXTRACTION ---

    // 1. DYNAMIC TOTAL ROW DETECTION
    // Loose check: look for "TOTAL" anywhere in the first column string
    const totalRowIndex = rows.findIndex(r => r[0] && String(r[0]).toUpperCase().includes("TOTAL"));

    if (totalRowIndex === -1) {
        throw new Error("❌ ERROR: NO SE ENCUENTRA LA FILA 'TOTAL'");
    }

    const totalRow = rows[totalRowIndex];

    // Col B (Index 1) = Orders
    const totalOrders = parseInteger(totalRow[1]);

    // Hourly Data: Parsing columns 2 to 12 (10h to 19h)
    const hourlyTotals: number[] = totalRow.slice(2, 12).map((val: string) => smartParseNumber(val));

    // CORRECTION: Data is CUMULATIVE. Use Max. 
    // Guard against empty array or all zeros/NaNs resulting in -Infinity
    const maxVal = Math.max(...hourlyTotals);
    const totalSales = isFinite(maxVal) ? maxVal : 0;

    // 2. TARGET (META)
    // User Update: Row 43 (Index 42). 
    // Previous was Row 42 (Index 41).
    let dailyTarget = 0;

    // Primary Check: Row 43 (Index 42)
    if (rows[42] && rows[42][1]) {
        dailyTarget = smartParseNumber(rows[42][1]);
    }

    // Fallback Check: Row 42 (Index 41) if Row 43 is empty
    if (dailyTarget === 0 && rows[41] && rows[41][1]) {
        console.warn("Row 43 empty? Falling back to Row 42 for Target.");
        dailyTarget = smartParseNumber(rows[41][1]);
    }

    // Safety Default to avoid Division by Zero
    if (dailyTarget === 0) dailyTarget = 1;

    // 3. ADVISORS
    const advisors: AdvisorData[] = [];

    for (let i = 1; i < totalRowIndex; i++) {
       const row = rows[i];
       if (!row || !row[0]) continue; // Skip if no name

       const name = row[0].trim();
       if (!name || name.toUpperCase() === 'TOTAL') continue;

       const orders = parseInteger(row[1]);

       const advisorHourlySales = row.slice(2, 12).map((val: string) => smartParseNumber(val));
       const maxAdvisorVal = Math.max(...advisorHourlySales);
       const advisorTotal = isFinite(maxAdvisorVal) ? maxAdvisorVal : 0;

       // Include if they have any activity or a valid name
       if (advisorTotal > 0 || orders > 0 || (name.length > 2 && name !== 'ASESOR')) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales: advisorHourlySales
         });
       }
    }

    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

