export const playCelebrationSound = () => {
  try {
    const ctx = getAudioContext();
    initAudio();
    const now = ctx.currentTime;

    // --- SYNTHESIZED OVATION / APPLAUSE ---
    // Instead of a melody, we create "Pink Noise" bursts to simulate a crowd cheering/clapping

    const duration = 4.0;
    const bufferSize = ctx.sampleRate * duration;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const data = buffer.getChannelData(0);

    // Generate Pink Noise (Approximation)
    // Pink noise sounds more natural (like rain/clapping) than White noise (static)
    let b0 = 0, b1 = 0, b2 = 0, b3 = 0, b4 = 0, b5 = 0, b6 = 0;
    for (let i = 0; i < bufferSize; i++) {
      const white = Math.random() * 2 - 1;

      b0 = 0.99886 * b0 + white * 0.0555179;
      b1 = 0.99332 * b1 + white * 0.0750759;
      b2 = 0.96900 * b2 + white * 0.1538520;
      b3 = 0.86650 * b3 + white * 0.3104856;
      b4 = 0.55000 * b4 + white * 0.5329522;
      b5 = -0.7616 * b5 - white * 0.0168980;

      data[i] = b0 + b1 + b2 + b3 + b4 + b5 + b6 + white * 0.5362;
      data[i] *= 0.11; // Compensate gain
      b6 = white * 0.115926;
    }

    const noise = ctx.createBufferSource();
    noise.buffer = buffer;

    // Filter to remove harsh high frequencies (makes it sound more like a distant crowd)
    const filter = ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 800; 

    // Gain Envelope for "Swell" effect
    const gain = ctx.createGain();
    gain.gain.setValueAtTime(0, now);
    gain.gain.linearRampToValueAtTime(0.5, now + 0.5); // Fade in (Crowd roaring)
    gain.gain.exponentialRampToValueAtTime(0.01, now + duration - 0.5); // Fade out

    noise.connect(filter);
    filter.connect(gain);
    gain.connect(ctx.destination);

    noise.start(now);

    // Add a few tonal "cheers" on top
    const noteFreqs = [523.25, 783.99]; // C and G
    noteFreqs.forEach((freq, idx) => {
        const osc = ctx.createOscillator();
        const oscGain = ctx.createGain();
        osc.connect(oscGain);
        oscGain.connect(ctx.destination);

        osc.type = 'triangle';
        osc.frequency.value = freq;

        oscGain.gain.setValueAtTime(0, now);
        oscGain.gain.linearRampToValueAtTime(0.05, now + 0.1);
        oscGain.gain.linearRampToValueAtTime(0, now + 1.5);

        osc.start(now + (idx * 0.2));
        osc.stop(now + 2.0);
    });

  } catch (e) {
    console.error("Error generating celebration sound", e);
  }
};

