    // Notes: C5, E5, G5, C6 (High C)

    const melody = [
      { freq: 523.25, startTime: 0.0, duration: 0.2 },   // Do (C5)
      { freq: 659.25, startTime: 0.15, duration: 0.2 },  // Mi (E5)
