import { CONFIG } from '../constants';
import { DashboardData, AdvisorData } from '../types';

// Declare PapaParse globally since we loaded it via CDN
declare const Papa: any;

// Helper: Delay for retry
const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Smart parsing to handle mixed locales (US vs AR).
 * Now robust against NaN and non-numeric garbage.
 */
const smartParseNumber = (value: string | undefined): number => {
  if (!value) return 0;
  let str = String(value).trim();

  // Aggressive cleanup: remove anything that isn't a digit, dot, comma, or minus
  // This handles "$", "ARS", spaces, hidden chars, etc.
  // Note: we preserve dots and commas for locale detection
  const cleanStrForDetection = str.replace(/[^\d.,-]/g, '');

  if (!cleanStrForDetection || cleanStrForDetection === '' || cleanStrForDetection === '-') return 0;

  let result = 0;
  const lastComma = cleanStrForDetection.lastIndexOf(',');
  const lastDot = cleanStrForDetection.lastIndexOf('.');

  // Scenario 1: Both separators present
  if (lastComma > -1 && lastDot > -1) {
    if (lastDot > lastComma) {
      // US Format (e.g. 1,234.56)
      result = parseFloat(cleanStrForDetection.replace(/,/g, ''));
    } else {
      // AR Format (e.g. 1.234,56)
      result = parseFloat(cleanStrForDetection.replace(/\./g, '').replace(',', '.'));
    }
  }
  // Scenario 2: Only Dot
  else if (lastDot > -1) {
    const dotCount = (cleanStrForDetection.match(/\./g) || []).length;
    if (dotCount > 1) {
      // 1.000.000 -> 1000000
      result = parseFloat(cleanStrForDetection.replace(/\./g, ''));
    } else if (/\.\d{3}$/.test(cleanStrForDetection)) {
       // 1.000 -> 1000 (Thousands)
       result = parseFloat(cleanStrForDetection.replace(/\./g, ''));
    } else {
       // 10.50 -> 10.5 (Decimal)
       result = parseFloat(cleanStrForDetection);
    }
  }
  // Scenario 3: Only Comma
  else if (lastComma > -1) {
    const commaCount = (cleanStrForDetection.match(/,/g) || []).length;
    if (commaCount > 1) {
      // 1,000,000 -> 1000000
      result = parseFloat(cleanStrForDetection.replace(/,/g, ''));
    } else if (/,\d{3}$/.test(cleanStrForDetection)) {
      // 1,000 -> 1000
      result = parseFloat(cleanStrForDetection.replace(/,/g, ''));
    } else {
      // 10,50 -> 10.5
      result = parseFloat(cleanStrForDetection.replace(',', '.'));
    }
  }
  // No separators
  else {
    result = parseFloat(cleanStrForDetection);
  }

  // Final safety check: if result is NaN, return 0
  return isNaN(result) ? 0 : result;
};

