      header: false,
      skipEmptyLines: false, 
    });

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- 1. DYNAMIC HEADER & COLUMN DETECTION ---

    // Find the Header Row (Look for 'PEDIDOS' or 'ASESOR' in first 10 rows)
    let headerRowIndex = rows.findIndex((r, idx) => idx < 10 && r.some(c => c && String(c).toUpperCase().includes('PEDIDOS')));
    if (headerRowIndex === -1) headerRowIndex = 0; // Fallback to first row

    const headerRow = rows[headerRowIndex];
    console.log(`📋 Header found at row ${headerRowIndex}:`, headerRow);

    // Detect "Pedidos" Column Index
    let ordersColIdx = headerRow.findIndex(c => c && String(c).toUpperCase().includes('PEDIDOS'));
    if (ordersColIdx === -1) {
        // Fallback: Check if there is a column 'ORDENES'
        ordersColIdx = headerRow.findIndex(c => c && String(c).toUpperCase().includes('ORDENES'));
    }
    if (ordersColIdx === -1) ordersColIdx = 1; // Default to B if fail
    console.log(`📦 Orders column detected at index: ${ordersColIdx}`);

    // Detect "Hours" Start Index (Look for '10:00' or similar)
    let hoursStartIdx = headerRow.findIndex(c => c && (String(c).includes('10:00') || String(c).replace(/\s/g, '').toUpperCase().includes('10HS')));
    if (hoursStartIdx === -1) hoursStartIdx = 2; // Default to C if fail
    console.log(`⏰ Hourly data starts at index: ${hoursStartIdx}`);


    // --- 2. FIND SPECIAL ROWS (TOTAL & TARGET) ---

    // Find TOTAL Row
    const totalRowIndex = rows.findIndex(r => r[0] && String(r[0]).toUpperCase().includes("TOTAL"));
    if (totalRowIndex === -1) throw new Error("❌ ERROR: NO SE ENCUENTRA LA FILA 'TOTAL'");

    const totalRow = rows[totalRowIndex];

    // Find META (Target) Row dynamically
    let dailyTarget = 0;
    const targetRow = rows.find(r => 
        r[0] && (String(r[0]).toUpperCase().includes("META") || String(r[0]).toUpperCase().includes("OBJETIVO"))
    );

    if (targetRow && targetRow[1]) {
        dailyTarget = smartParseNumber(targetRow[1]); // Meta usually in Col B, or we could use ordersColIdx if meta is sales? Usually Meta is Sales.
        // If meta is sales, it might be in column B (index 1) even if orders are elsewhere, but usually Meta is single cell.
        // Let's assume Meta is in column 1 (B) as per standard templates, or try to be smart.
        // Actually, if orders moved, Meta value might be in `ordersColIdx` or standard col 1.
        // Let's try parsing the cell at column 1 first.
    }

    // Fallback Legacy Meta
    if (dailyTarget === 0) {
        if (rows[42] && rows[42][1]) dailyTarget = smartParseNumber(rows[42][1]);
        else if (rows[41] && rows[41][1]) dailyTarget = smartParseNumber(rows[41][1]);
    }
    if (dailyTarget === 0) dailyTarget = 1;


    // --- 3. EXTRACT METRICS ---

    // Total Orders from TOTAL row at detected column
    const totalOrders = parseInteger(totalRow[ordersColIdx]);

    // Total Hourly Sales from TOTAL row
    // Slice 10 columns starting from detected start index
    const hourlyTotals: number[] = totalRow.slice(hoursStartIdx, hoursStartIdx + 10).map((val: string) => smartParseNumber(val));

    // Cumulative Total Sales
    const maxVal = Math.max(...hourlyTotals);
    const totalSales = isFinite(maxVal) ? maxVal : 0;


    // --- 4. EXTRACT ADVISORS ---

    const advisors: AdvisorData[] = [];

    // Iterate from row AFTER header until Total row
    for (let i = headerRowIndex + 1; i < totalRowIndex; i++) {
       const row = rows[i];
       if (!row || !row[0]) continue; 

       const name = row[0].trim();
       // Skip noise rows
       if (!name || name.toUpperCase() === 'TOTAL' || name.toUpperCase() === 'META' || name.toUpperCase() === 'OBJETIVO') continue;

       // Use detected indices
       const orders = parseInteger(row[ordersColIdx]);

       const advisorHourlySales = row.slice(hoursStartIdx, hoursStartIdx + 10).map((val: string) => smartParseNumber(val));
       const maxAdvisorVal = Math.max(...advisorHourlySales);
       const advisorTotal = isFinite(maxAdvisorVal) ? maxAdvisorVal : 0;

       // Filter empty rows
       if (advisorTotal > 0 || orders > 0 || (name.length > 2 && name !== 'ASESOR')) {
         advisors.push({
             name,
             orders,
             totalSales: advisorTotal,
             hourlySales: advisorHourlySales
         });
       }
    }

    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales,
      totalOrders,
      dailyTarget,
      hourlyTotals,
      lastUpdated: new Date()
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

