export const fetchDashboardData = async (): Promise<DashboardData> => {
  try {
    const csvText = await fetchWithRobustRetry(CONFIG.SHEET_URL);

    const parseResult = Papa.parse(csvText, {
      header: false,
      skipEmptyLines: false, 
    });

    const rows: string[][] = parseResult.data;

    if (!rows || rows.length === 0) {
      throw new Error('No data found in CSV');
    }

    // --- 1. DYNAMIC HEADER & COLUMN DETECTION ---

    // Find the Header Row (Look for 'PEDIDOS' or 'ASESOR' in first 10 rows)
    let headerRowIndex = rows.findIndex((r, idx) => idx < 10 && r.some(c => c && String(c).toUpperCase().includes('PEDIDOS')));
    if (headerRowIndex === -1) headerRowIndex = 0; 

    const headerRow = rows[headerRowIndex];
    console.log(`📋 Header found at row ${headerRowIndex}:`, headerRow);

    // Detect "Pedidos" Column Index
    let ordersColIdx = headerRow.findIndex(c => c && String(c).toUpperCase().includes('PEDIDOS'));
    if (ordersColIdx === -1) {
        ordersColIdx = headerRow.findIndex(c => c && String(c).toUpperCase().includes('ORDENES'));
    }
    if (ordersColIdx === -1) ordersColIdx = 1; // Default to B
    console.log(`📦 Orders column detected at index: ${ordersColIdx}`);

    // Detect "Hours" Start Index (Look for '10:00')
    let hoursStartIdx = headerRow.findIndex(c => c && (String(c).includes('10:00') || String(c).replace(/\s/g, '').toUpperCase().includes('10HS')));
    if (hoursStartIdx === -1) hoursStartIdx = 2; // Default to C
    console.log(`⏰ Hourly data starts at index: ${hoursStartIdx}`);


    // --- 2. FIND SPECIAL META-DATA (TARGET & VERSION) ---

    let dailyTarget = 0;
    let systemVersion = '1.0'; // Default version

    // Scan for Special keys in Column A
    rows.forEach(r => {
        if (!r[0]) return;
        const key = String(r[0]).trim().toUpperCase();
        const value = r[1] ? String(r[1]).trim() : '';

        // TARGET
        if (key.includes('META') || key.includes('OBJETIVO')) {
            dailyTarget = smartParseNumber(value);
        }

        // REMOTE RELOAD VERSION
        if (key === 'VERSION' || key === 'REINICIAR' || key === 'SISTEMA') {
            if (value.length > 0) {
                systemVersion = value;
                console.log("🔄 Detected System Version:", systemVersion);
            }
        }
    });

    // Priority 2: Hardcoded Fallback for Target (Row 22 / Index 21)
    if (dailyTarget === 0 && rows.length > 21) {
        const fallbackRow = rows[21];
        if (fallbackRow && fallbackRow[1]) {
             dailyTarget = smartParseNumber(fallbackRow[1]);
        }
    }
    if (dailyTarget === 0) dailyTarget = 1;


    // --- 3. EXTRACT ADVISORS (THE CORE TRUTH) ---

    // Find TOTAL Row to define the end of the list
    const totalRowIndex = rows.findIndex(r => r[0] && String(r[0]).toUpperCase().includes("TOTAL"));
    // If no total row found, assume end of file
    const endRowIndex = totalRowIndex !== -1 ? totalRowIndex : rows.length;

    const advisors: AdvisorData[] = [];

    // Strict iteration from Header+1 to TotalRow-1
    for (let i = headerRowIndex + 1; i < endRowIndex; i++) {
       const row = rows[i];
       if (!row || !row[0]) continue; 

       const rawName = String(row[0]).trim();
       const upperName = rawName.toUpperCase();

       // EXCLUSION LIST: Filter out non-advisor rows
       if (
           rawName === '' || 
           upperName === 'ASESOR' || // Header repetition
           upperName === 'TOTAL' || 
           upperName.includes('OBJETIVO') || 
           upperName.includes('META') ||
           upperName === 'VERSION' ||
           upperName === 'REINICIAR' ||
           upperName === 'SISTEMA'
       ) {
           continue;
       }

       // If the name is valid (length > 1), we INCLUDE it, even if sales are 0.
       if (rawName.length > 1) {
           const orders = parseInteger(row[ordersColIdx]);
           const advisorHourlySales = row.slice(hoursStartIdx, hoursStartIdx + 10).map((val: string) => smartParseNumber(val));
           const maxAdvisorVal = Math.max(...advisorHourlySales);
           const totalSales = isFinite(maxAdvisorVal) ? maxAdvisorVal : 0;

           advisors.push({
               name: rawName,
               orders,
               totalSales,
               hourlySales: advisorHourlySales
           });
       }
    }

    // --- 4. CALCULATE AGGREGATES MANUALLY ---

    const calculatedTotalOrders = advisors.reduce((sum, adv) => sum + adv.orders, 0);
    const calculatedTotalSales = advisors.reduce((sum, adv) => sum + adv.totalSales, 0);

    // Calculate Hourly Totals by summing columns vertically
    const calculatedHourlyTotals: number[] = Array(10).fill(0);

    advisors.forEach(adv => {
        adv.hourlySales.forEach((val, idx) => {
            if (idx < 10) {
                calculatedHourlyTotals[idx] += val;
            }
        });
    });

    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales: calculatedTotalSales,
      totalOrders: calculatedTotalOrders,
      dailyTarget,
      hourlyTotals: calculatedHourlyTotals,
      lastUpdated: new Date(),
      systemVersion // Return the detected version
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

