       }
    }

    // --- 4. CALCULATE AGGREGATES MANUALLY ---

    const calculatedTotalOrders = advisors.reduce((sum, adv) => sum + adv.orders, 0);
    const calculatedTotalSales = advisors.reduce((sum, adv) => sum + adv.totalSales, 0);

    // Calculate Hourly Totals by summing columns vertically
    const calculatedHourlyTotals: number[] = Array(10).fill(0);

    advisors.forEach(adv => {
        adv.hourlySales.forEach((val, idx) => {
            if (idx < 10) {
                calculatedHourlyTotals[idx] += val;
            }
        });
    });

    advisors.sort((a, b) => b.totalSales - a.totalSales);

    return {
      advisors,
      totalSales: calculatedTotalSales,
      totalOrders: calculatedTotalOrders,
      dailyTarget,
      hourlyTotals: calculatedHourlyTotals,
      lastUpdated: new Date(),
      systemVersion // Return the detected version/token
    };

  } catch (error) {
    console.error('Error fetching/parsing dashboard data:', error);
    throw error;
  }
};

import React, { useEffect, useState, useCallback, useRef } from 'react';
import { fetchDashboardData } from './services/sheetService';
import { playNotificationSound, playCelebrationSound, initAudio } from './services/soundService';
import { DashboardData } from './types';
import { KpiCard } from './components/KpiCard';
import { TopPerformerCard } from './components/TopPerformerCard';
import { HourlyBlock } from './components/HourlyBlock';
import { AdvisorBarChart, EvolutionLineChart } from './components/Charts';
import { COLORS, CONFIG, HOURS } from './constants';

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('es-AR', {
    style: 'currency',
    currency: 'ARS',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(value);
};

const App: React.FC = () => {
  const [data, setData] = useState<DashboardData | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [lastRefresh, setLastRefresh] = useState<Date>(new Date());

  // Celebration & Sound State
  const [celebrationMode, setCelebrationMode] = useState<boolean>(false);
  const [audioEnabled, setAudioEnabled] = useState<boolean>(false);
  const hasCelebratedRef = useRef<boolean>(false);

  // Track previous sales to detect updates
  const prevTotalSalesRef = useRef<number>(0);

  const loadData = useCallback(async () => {
    try {
      setError(null);
      const dashboardData = await fetchDashboardData();

      // --- REMOTE RELOAD CHECK (PERSISTENT) ---
      // We compare the version coming from the Sheet with what we have stored in localStorage.
      // If they differ, it means the admin issued a "RECARGAR" command.
      const remoteVersion = dashboardData.systemVersion;
      const localVersion = localStorage.getItem('FARM_DASH_VERSION');

      if (remoteVersion && remoteVersion !== localVersion) {
          console.log(`🔄 Reload Command Detected! Remote: ${remoteVersion} vs Local: ${localVersion}`);
          // Update local storage so we don't reload again until it changes
          localStorage.setItem('FARM_DASH_VERSION', remoteVersion);
          // Force reload
          window.location.reload();
          return; 
      }

      // Check for Sales Increase (Data Update Sound)
      if (prevTotalSalesRef.current > 0 && dashboardData.totalSales > prevTotalSalesRef.current) {
          console.log("💰 Sales increased!", { prev: prevTotalSalesRef.current, new: dashboardData.totalSales, audioEnabled });

          if (audioEnabled) {
              playNotificationSound();
          }
      }
      // Update reference for next cycle
      prevTotalSalesRef.current = dashboardData.totalSales;

      setData(dashboardData);
      setLastRefresh(new Date());

      // Check Celebration Condition (Target Hit)
      if (dashboardData.totalSales >= dashboardData.dailyTarget && dashboardData.totalSales > 0 && dashboardData.dailyTarget > 1) {
        setCelebrationMode(true);
      } else {
        setCelebrationMode(false);
        hasCelebratedRef.current = false; 
      }

    } catch (err) {
      console.error(err);
      setError('⚠️ Reintentando...');
    } finally {
      setLoading(false);
    }
  }, [audioEnabled]); 

  // Celebration Audio Effect Logic
  useEffect(() => {
    if (celebrationMode && !hasCelebratedRef.current && audioEnabled) {
      playCelebrationSound();
      hasCelebratedRef.current = true;
    }
  }, [celebrationMode, audioEnabled]);

  useEffect(() => {
    loadData();
    const intervalId = setInterval(loadData, CONFIG.REFRESH_INTERVAL_MS);
    return () => clearInterval(intervalId);
  }, [loadData]);

  const toggleAudio = () => {
    const newState = !audioEnabled;
    setAudioEnabled(newState);

    // Immediate feedback to user AND unlock AudioContext
    if (newState) {
        initAudio();
        playNotificationSound();
    }
  };

  if (loading && !data) {
    return (
      <div className="flex h-screen w-screen items-center justify-center bg-[#0b0e14] text-white">
        <div className="flex flex-col items-center gap-4">
           <p className="text-[#325795] font-mono text-sm uppercase font-bold animate-pulse">Conectando con Google Sheets...</p>
        </div>
      </div>
    );
  }

  const totalSales = data?.totalSales || 0;
  const totalOrders = data?.totalOrders || 0;
  const target = data?.dailyTarget || 1;
  const progress = totalSales / target;
  const topPerformer = data?.advisors[0]; 

  return (
    <div className={`h-screen w-screen flex flex-col p-4 2xl:p-6 transition-all duration-1000 ease-in-out font-sans overflow-hidden select-none
        ${celebrationMode 
          ? 'bg-gradient-to-l from-[#C8102E] via-[#325795] to-[#01B693] bg-[length:400%_400%] animate-[gradientAnim_8s_ease_infinite]' 
          : 'bg-[#0b0e14]'
        }`}>

        {/* Ambient Background Glow for Standard Mode */}
        {!celebrationMode && (
          <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
             <div className="absolute top-[-20%] left-[-10%] w-[50%] h-[50%] rounded-full bg-[#325795] opacity-[0.05] blur-[150px]"></div>
             <div className="absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] rounded-full bg-[#325795] opacity-[0.05] blur-[150px]"></div>
          </div>
        )}

        <style>{`
          @keyframes gradientAnim {
              0%{background-position:0% 50%}
              50%{background-position:100% 50%}
              100%{background-position:0% 50%}
          }
        `}</style>

      {/* Header - Ultra Compact */}
      <div className="flex justify-between items-center mb-2 shrink-0 relative z-10 bg-white/5 p-2 rounded-xl backdrop-blur-sm border border-white/5">
        <div className="flex items-center gap-4">
            {/* Logo */}
            <div className="bg-white/10 p-1.5 rounded-lg">
                <img 
                    src="https://ugc.production.linktr.ee/5ef65f71-15a5-4bc2-8e40-71e49e3483e5_FarmaPlus-ORIGINAL-H.png" 
                    alt="Logo" 
                    className="h-5 2xl:h-6 object-contain"
                />
            </div>

            {/* Status */}
            <div className="flex items-center gap-2 border-l border-white/10 pl-4">
              <div className={`w-1.5 h-1.5 rounded-full ${error ? 'bg-yellow-500' : 'bg-[#01B693] shadow-[0_0_8px_#01B693] animate-pulse'}`}></div>
              <p className="text-[10px] 2xl:text-xs text-gray-400 font-bold tracking-wide">
                ACTUALIZADO: <span className="text-white font-mono ml-1">{lastRefresh.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit', second: '2-digit'})}</span>
              </p>
            </div>
        </div>

        {/* Controls */}
        <div className="flex items-center gap-3">
            <button 
                onClick={toggleAudio}
                className={`px-3 py-1 rounded-lg border text-[10px] 2xl:text-xs font-bold transition-all hover:bg-white/5 cursor-pointer active:scale-95
                    ${audioEnabled 
                    ? 'bg-green-900/20 border-[#01B693]/50 text-[#01B693]' 
                    : 'bg-white/5 border-white/10 text-gray-500'
                    }`}>
                {audioEnabled ? '🔊 SONIDO ON' : '🔇 SONIDO OFF'}
            </button>
        </div>
      </div>

      {/* ROW 1: KPIs + Top Performer */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3 2xl:gap-5 mb-3 shrink-0 relative z-10">
        <KpiCard
          title="Facturación Total"
          value={formatCurrency(totalSales)}
          color={COLORS.BLUE}
        />
        <KpiCard
          title="Pedidos"
          value={totalOrders.toString()}
          color={COLORS.RED}
        />
        <KpiCard
          title="% Cumplimiento"
          value={`${Math.round(progress * 100)}%`}
          color={COLORS.GREEN}
          percentage={progress}
        />
        <TopPerformerCard 
          advisor={topPerformer} 
          totalSales={totalSales} 
        />
      </div>

      {/* ROW 2: Hourly Blocks */}
      <div className="flex gap-2 2xl:gap-4 mb-3 shrink-0 overflow-x-auto pb-1 scrollbar-hide relative z-10 h-20 2xl:h-24">
        {HOURS.map((hour, index) => (
          <HourlyBlock 
            key={hour} 
            hour={hour} 
            value={data?.hourlyTotals[index] || 0}
          />
        ))}
      </div>

      {/* ROW 3: Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-3 2xl:gap-5 flex-1 min-h-0 relative z-10">

        {/* Advisor Ranking */}
        <div className="bg-[#121620] p-4 2xl:p-6 rounded-2xl border border-white/5 flex flex-col shadow-2xl relative backdrop-blur-md overflow-hidden">
            <div className="flex-1 min-h-0 relative overflow-hidden">
                 {data && <AdvisorBarChart advisors={data.advisors} />}
            </div>
        </div>

        {/* Evolution Chart */}
        <div className="bg-[#121620] p-4 2xl:p-6 rounded-2xl border border-white/5 flex flex-col shadow-2xl relative backdrop-blur-md overflow-hidden">
             <div className="flex-1 min-h-0 relative">
                {data && <EvolutionLineChart hourlyTotals={data.hourlyTotals} />}
            </div>
        </div>
      </div>

    </div>
  );
};

export default App;
